content.content:
1	/* ============================================================
2	   MAXIWORX 2026 — components.css
3	   Hamburger, Mobile-Nav, Studio-Page, allgemeine Komponenten
4	   ============================================================ */
5	
6	/* ------------------------------------------------------------
7	   HAMBURGER BUTTON
8	   ------------------------------------------------------------ */
9	.hamburger {
10	  display: none;
11	  flex-direction: column;
12	  justify-content: center;
13	  align-items: center;
14	  gap: 5px;
15	  width: 36px;
16	  height: 36px;
17	  cursor: pointer;
18	  background: none;
19	  border: none;
20	  padding: 4px;
21	  z-index: 200;
22	  flex-shrink: 0;
23	}
24	
25	.hamburger__line {
26	  display: block;
27	  width: 22px;
28	  height: 1.5px;
29	  background: rgba(240, 237, 232, 0.75);
30	  border-radius: 2px;
31	  transform-origin: center;
32	  transition: transform 300ms ease, opacity 300ms ease, width 300ms ease;
33	}
34	
35	/* Aktiv-Zustand: X */
36	.hamburger.is-open .hamburger__line:nth-child(1) {
37	  transform: translateY(6.5px) rotate(45deg);
38	}
39	.hamburger.is-open .hamburger__line:nth-child(2) {
40	  opacity: 0;
41	  width: 0;
42	}
43	.hamburger.is-open .hamburger__line:nth-child(3) {
44	  transform: translateY(-6.5px) rotate(-45deg);
45	}
46	
47	/* ------------------------------------------------------------
48	   MOBILE NAV OVERLAY
49	   ------------------------------------------------------------ */
50	.mobile-nav {
51	  position: fixed;
52	  inset: 0;
53	  z-index: 90;
54	  display: flex;
55	  flex-direction: column;
56	  align-items: center;
57	  justify-content: center;
58	  gap: 2.5rem;
59	
60	  background: rgba(6, 6, 5, 0.97);
61	  backdrop-filter: blur(24px);
62	  -webkit-backdrop-filter: blur(24px);
63	
64	  opacity: 0;
65	  pointer-events: none;
66	  transform: translateY(-12px);
67	  transition: opacity 350ms ease, transform 350ms ease;
68	}
69	
70	.mobile-nav.is-open {
71	  opacity: 1;
72	  pointer-events: all;
73	  transform: translateY(0);
74	}
75	
76	.mobile-nav__links {
77	  display: flex;
78	  flex-direction: column;
79	  align-items: center;
80	  gap: 0.25rem;
81	  list-style: none;
82	}
83	
84	.mobile-nav__link {
85	  font-family: 'Cormorant Garamond', serif;
86	  font-size: clamp(2rem, 7vw, 3rem);
87	  font-weight: 300;
88	  letter-spacing: 0.08em;
89	  color: rgba(240, 237, 232, 0.55);
90	  transition: color 200ms ease;
91	  padding: 0.4rem 1rem;
92	  display: block;
93	  text-align: center;
94	}
95	
96	.mobile-nav__link:hover {
97	  color: #F0EDE8;
98	}
99	
100	.mobile-nav__link.active {
101	  color: #C8922A;
102	}
103	
104	.mobile-nav__divider {
105	  width: 40px;
106	  height: 1px;
107	  background: rgba(200, 146, 42, 0.25);
108	}
109	
110	.mobile-nav__cta {
111	  font-family: 'Inter', sans-serif;
112	  font-size: 0.813rem;
113	  font-weight: 500;
114	  letter-spacing: 0.12em;
115	  text-transform: uppercase;
116	  color: #fff;
117	  background: #3A7BD5;
118	  border: 1px solid #3A7BD5;
119	  border-radius: 9999px;
120	  padding: 0.75rem 2.5rem;
121	  transition: background 200ms, box-shadow 200ms;
122	  margin-top: 0.5rem;
123	}
124	
125	.mobile-nav__cta:hover {
126	  background: #4A8BE5;
127	  box-shadow: 0 4px 20px rgba(58, 123, 213, 0.35);
128	}
129	
130	.mobile-nav__lang {
131	  display: flex;
132	  align-items: center;
133	  gap: 1rem;
134	  margin-top: 0.5rem;
135	}
136	
137	.mobile-lang-btn {
138	  display: flex;
139	  align-items: center;
140	  gap: 0.5rem;
141	  font-size: 0.75rem;
142	  font-weight: 500;
143	  letter-spacing: 0.10em;
144	  text-transform: uppercase;
145	  color: rgba(255, 255, 255, 0.30);
146	  background: none;
147	  border: 1px solid rgba(255, 255, 255, 0.08);
148	  border-radius: 9999px;
149	  padding: 0.35rem 0.875rem;
150	  cursor: pointer;
151	  transition: color 200ms, border-color 200ms;
152	}
153	
154	.mobile-lang-btn.active {
155	  color: #C8922A;
156	  border-color: rgba(200, 146, 42, 0.35);
157	}
158	
159	.mobile-lang-btn svg {
160	  width: 16px;
161	  height: 16px;
162	  border-radius: 2px;
163	}
164	
165	/* ------------------------------------------------------------
166	   RESPONSIVE NAV — Hamburger einblenden
167	   ------------------------------------------------------------ */
168	@media (max-width: 960px) {
169	  .nav-links   { display: none !important; }
170	  .hamburger   { display: flex; }
171	  .lang-switcher { display: none; } /* Im Mobile-Nav übernommen */
172	}
173	
174	/* ------------------------------------------------------------
175	   PAGE HERO (Unterseiten — kein Fullscreen)
176	   ------------------------------------------------------------ */
177	.page-hero {
178	  position: relative;
179	  padding: 9rem 0 5rem;
180	  text-align: center;
181	  z-index: 10;
182	}
183	
184	.page-hero__label {
185	  font-size: 0.688rem;
186	  font-weight: 500;
187	  letter-spacing: 0.28em;
188	  text-transform: uppercase;
189	  color: #C8922A;
190	  margin-bottom: 1rem;
191	  opacity: 0;
192	  animation: fadeUp 0.8s ease 0.2s forwards;
193	}
194	
195	.page-hero__title {
196	  font-family: 'Cormorant Garamond', serif;
197	  font-size: clamp(3rem, 8vw, 6.5rem);
198	  font-weight: 300;
199	  letter-spacing: 0.12em;
200	  text-transform: uppercase;
201	  color: #F0EDE8;
202	  line-height: 1.0;
203	  text-shadow: 0 2px 40px rgba(0, 0, 0, 0.8);
204	  opacity: 0;
205	  animation: fadeUp 1s ease 0.4s forwards;
206	}
207	
208	.page-hero__sub {
209	  font-family: 'Cormorant Garamond', serif;
210	  font-style: italic;
211	  font-size: clamp(0.875rem, 2vw, 1.125rem);
212	  font-weight: 300;
213	  letter-spacing: 0.20em;
214	  color: rgba(200, 146, 42, 0.7);
215	  margin-top: 1rem;
216	  opacity: 0;
217	  animation: fadeUp 1s ease 0.6s forwards;
218	}
219	
220	/* Gold-Linie unter Page-Hero */
221	.page-hero__line {
222	  width: 60px;
223	  height: 1px;
224	  background: linear-gradient(to right, transparent, #C8922A, transparent);
225	  margin: 2rem auto 0;
226	  opacity: 0;
227	  animation: fadeIn 1s ease 0.8s forwards;
228	}
229	
230	@keyframes fadeUp { from { opacity:0; transform:translateY(16px); } to { opacity:1; transform:translateY(0); } }
231	@keyframes fadeIn { from { opacity:0; } to { opacity:1; } }
232	
233	/* ------------------------------------------------------------
234	   STUDIO PAGE — Raumkarten
235	   ------------------------------------------------------------ */
236	
237	/* Intro-Section */
238	.studio-intro {
239	  padding: 0 0 5rem;
240	}
241	
242	.studio-intro__glass {
243	  background: rgba(16, 15, 13, 0.65);
244	  backdrop-filter: blur(24px) saturate(1.3);
245	  -webkit-backdrop-filter: blur(24px) saturate(1.3);
246	  border: 1px solid rgba(255, 255, 255, 0.07);
247	  border-radius: 20px;
248	  padding: 3rem 3.5rem;
249	  position: relative;
250	  overflow: hidden;
251	}
252	
253	.studio-intro__glass::before {
254	  content: '';
255	  position: absolute;
256	  top: -80px; left: -80px;
257	  width: 320px; height: 320px;
258	  background: radial-gradient(circle, rgba(200, 146, 42, 0.06) 0%, transparent 65%);
259	  pointer-events: none;
260	}
261	
262	.studio-intro__label {
263	  font-size: 0.688rem;
264	  font-weight: 500;
265	  letter-spacing: 0.25em;
266	  text-transform: uppercase;
267	  color: #C8922A;
268	  margin-bottom: 0.75rem;
269	}
270	
271	.studio-intro__title {
272	  font-family: 'Cormorant Garamond', serif;
273	  font-size: clamp(1.5rem, 3vw, 2.25rem);
274	  font-weight: 300;
275	  color: #F0EDE8;
276	  line-height: 1.2;
277	  margin-bottom: 1.5rem;
278	}
279	
280	.studio-intro__text {
281	  font-size: 0.938rem;
282	  font-weight: 300;
283	  color: rgba(168, 164, 158, 0.9);
284	  line-height: 1.85;
285	  max-width: 720px;
286	}
287	
288	/* Raumkarten Grid */
289	.rooms-grid {
290	  display: grid;
291	  grid-template-columns: repeat(2, 1fr);
292	  gap: 1.5rem;
293	  padding: 0 0 5rem;
294	}
295	
296	.room-card {
297	  background: rgba(14, 14, 12, 0.70);
298	  backdrop-filter: blur(16px);
299	  -webkit-backdrop-filter: blur(16px);
300	  border: 1px solid rgba(255, 255, 255, 0.06);
301	  border-radius: 16px;
302	  overflow: hidden;
303	  transition: border-color 300ms ease, box-shadow 300ms ease;
304	}
305	
306	.room-card:hover {
307	  border-color: rgba(200, 146, 42, 0.22);
308	  box-shadow: 0 12px 40px rgba(0, 0, 0, 0.4), 0 0 0 1px rgba(200, 146, 42, 0.08);
309	}
310	
311	/* Foto-Bereich */
312	.room-card__image {
313	  position: relative;
314	  aspect-ratio: 16 / 9;
315	  background: #0e0e0c;
316	  overflow: hidden;
317	}
318	
319	.room-card__image img {
320	  width: 100%;
321	  height: 100%;
322	  object-fit: cover;
323	  filter: brightness(0.75) saturate(0.8);
324	  transition: transform 600ms ease, filter 600ms ease;
325	}
326	
327	.room-card:hover .room-card__image img {
328	  transform: scale(1.03);
329	  filter: brightness(0.85) saturate(0.9);
330	}
331	
332	/* Platzhalter wenn kein Foto */
333	.room-card__placeholder {
334	  position: absolute;
335	  inset: 0;
336	  display: flex;
337	  align-items: center;
338	  justify-content: center;
339	  font-size: 0.688rem;
340	  letter-spacing: 0.15em;
341	  text-transform: uppercase;
342	  color: rgba(255, 255, 255, 0.10);
343	}
344	
345	.room-card__placeholder--a {
346	  background: radial-gradient(ellipse at 40% 50%, rgba(200,146,42,0.12) 0%, #0d0d0b 65%);
347	}
348	.room-card__placeholder--b {
349	  background: radial-gradient(ellipse at 60% 40%, rgba(58,123,213,0.10) 0%, #0d0d0b 65%);
350	}
351	.room-card__placeholder--c {
352	  background: radial-gradient(ellipse at 45% 55%, rgba(80,70,50,0.14) 0%, #0d0d0b 65%);
353	}
354	.room-card__placeholder--d {
355	  background: radial-gradient(ellipse at 55% 45%, rgba(40,60,80,0.12) 0%, #0d0d0b 65%);
356	}
357	
358	/* Raum-Tag auf dem Foto */
359	.room-card__tag {
360	  position: absolute;
361	  top: 1rem;
362	  left: 1rem;
363	  font-size: 0.625rem;
364	  font-weight: 500;
365	  letter-spacing: 0.16em;
366	  text-transform: uppercase;
367	  color: rgba(200, 146, 42, 0.9);
368	  background: rgba(8, 8, 6, 0.75);
369	  backdrop-filter: blur(8px);
370	  border: 1px solid rgba(200, 146, 42, 0.20);
371	  border-radius: 9999px;
372	  padding: 0.3rem 0.75rem;
373	}
374	
375	/* Inhalt */
376	.room-card__body {
377	  padding: 1.75rem 2rem 2rem;
378	}
379	
380	.room-card__title {
381	  font-family: 'Cormorant Garamond', serif;
382	  font-size: 1.375rem;
383	  font-weight: 400;
384	  color: #F0EDE8;
385	  margin-bottom: 0.5rem;
386	  line-height: 1.2;
387	}
388	
389	.room-card__subtitle {
390	  font-size: 0.688rem;
391	  font-weight: 500;
392	  letter-spacing: 0.16em;
393	  text-transform: uppercase;
394	  color: #C8922A;
395	  margin-bottom: 1.25rem;
396	}
397	
398	.room-card__desc {
399	  font-size: 0.875rem;
400	  font-weight: 300;
401	  color: rgba(168, 164, 158, 0.85);
402	  line-height: 1.8;
403	  margin-bottom: 1.75rem;
404	}
405	
406	/* Specs-Grid */
407	.room-specs {
408	  display: grid;
409	  grid-template-columns: repeat(3, 1fr);
410	  gap: 0.75rem;
411	  margin-bottom: 1.75rem;
412	}
413	
414	.spec-item {
415	  background: rgba(255, 255, 255, 0.03);
416	  border: 1px solid rgba(255, 255, 255, 0.05);
417	  border-radius: 8px;
418	  padding: 0.75rem 0.625rem;
419	  text-align: center;
420	}
421	
422	.spec-item__value {
423	  font-family: 'Cormorant Garamond', serif;
424	  font-size: 1.125rem;
425	  font-weight: 400;
426	  color: #F0EDE8;
427	  line-height: 1.2;
428	  margin-bottom: 0.2rem;
429	}
430	
431	.spec-item__label {
432	  font-size: 0.575rem;
433	  font-weight: 500;
434	  letter-spacing: 0.14em;
435	  text-transform: uppercase;
436	  color: rgba(255, 255, 255, 0.28);
437	}
438	
439	/* Gear-Tags */
440	.room-gear {
441	  display: flex;
442	  flex-wrap: wrap;
443	  gap: 0.4rem;
444	}
445	
446	.gear-tag {
447	  font-size: 0.625rem;
448	  font-weight: 400;
449	  letter-spacing: 0.08em;
450	  color: rgba(168, 164, 158, 0.65);
451	  background: rgba(255, 255, 255, 0.03);
452	  border: 1px solid rgba(255, 255, 255, 0.07);
453	  border-radius: 4px;
454	  padding: 0.25rem 0.6rem;
455	  transition: color 200ms, border-color 200ms;
456	}
457	
458	.gear-tag:hover {
459	  color: #C8922A;
460	  border-color: rgba(200, 146, 42, 0.25);
461	}
462	
463	/* Volle Breite (für besondere Räume) */
464	.room-card--full {
465	  grid-column: span 2;
466	}
467	
468	.room-card--full .room-card__image {
469	  aspect-ratio: 21 / 8;
470	}
471	
472	.room-card--full .room-card__body {
473	  display: grid;
474	  grid-template-columns: 1fr 1fr;
475	  gap: 2.5rem;
476	  align-items: start;
477	}
478	
479	.room-card--full .room-card__desc {
480	  margin-bottom: 0;
481	}
482	
483	/* ------------------------------------------------------------
484	   BUCHUNGS-CTA SECTION
485	   ------------------------------------------------------------ */
486	.booking-cta {
487	  padding: 5rem 0 6rem;
488	}
489	
490	.booking-cta__inner {
491	  background: rgba(16, 15, 13, 0.65);
492	  backdrop-filter: blur(24px) saturate(1.3);
493	  -webkit-backdrop-filter: blur(24px) saturate(1.3);
494	  border: 1px solid rgba(255, 255, 255, 0.07);
495	  border-radius: 20px;
496	  padding: 3.5rem 4rem;
497	  display: flex;
498	  align-items: center;
499	  justify-content: space-between;
500	  gap: 3rem;
501	  position: relative;
502	  overflow: hidden;
503	}
504	
505	.booking-cta__inner::after {
506	  content: '';
507	  position: absolute;
508	  bottom: -60px; right: -60px;
509	  width: 280px; height: 280px;
510	  background: radial-gradient(circle, rgba(58, 123, 213, 0.06) 0%, transparent 65%);
511	  pointer-events: none;
512	}
513	
514	.booking-cta__title {
515	  font-family: 'Cormorant Garamond', serif;
516	  font-size: clamp(1.5rem, 3vw, 2.25rem);
517	  font-weight: 300;
518	  color: #F0EDE8;
519	  line-height: 1.2;
520	  margin-bottom: 0.75rem;
521	}
522	
523	.booking-cta__desc {
524	  font-size: 0.875rem;
525	  font-weight: 300;
526	  color: rgba(168, 164, 158, 0.8);
527	  line-height: 1.75;
528	  max-width: 500px;
529	}
530	
531	.btn-cta-primary {
532	  display: inline-flex;
533	  align-items: center;
534	  gap: 0.6rem;
535	  font-family: 'Inter', sans-serif;
536	  font-size: 0.813rem;
537	  font-weight: 500;
538	  letter-spacing: 0.10em;
539	  text-transform: uppercase;
540	  color: #fff;
541	  background: #3A7BD5;
542	  border: 1px solid #3A7BD5;
543	  border-radius: 9999px;
544	  padding: 0.875rem 2rem;
545	  white-space: nowrap;
546	  flex-shrink: 0;
547	  cursor: pointer;
548	  transition: background 200ms, box-shadow 200ms, transform 150ms;
549	}
550	
551	.btn-cta-primary:hover {
552	  background: #4A8BE5;
553	  box-shadow: 0 8px 28px rgba(58, 123, 213, 0.35);
554	  transform: translateY(-2px);
555	}
556	
557	/* ------------------------------------------------------------
558	   RESPONSIVE
559	   ------------------------------------------------------------ */
560	@media (max-width: 960px) {
561	  .rooms-grid {
562	    grid-template-columns: 1fr;
563	  }
564	
565	  .room-card--full {
566	    grid-column: span 1;
567	  }
568	
569	  .room-card--full .room-card__image {
570	    aspect-ratio: 16 / 9;
571	  }
572	
573	  .room-card--full .room-card__body {
574	    grid-template-columns: 1fr;
575	    gap: 1.5rem;
576	  }
577	
578	  .booking-cta__inner {
579	    flex-direction: column;
580	    align-items: flex-start;
581	    padding: 2.5rem 2rem;
582	    gap: 2rem;
583	  }
584	
585	  .studio-intro__glass {
586	    padding: 2rem 1.75rem;
587	  }
588	}
589	
590	@media (max-width: 600px) {
591	  .room-card__body {
592	    padding: 1.25rem 1.25rem 1.5rem;
593	  }
594	
595	  .room-specs {
596	    grid-template-columns: repeat(3, 1fr);
597	    gap: 0.5rem;
598	  }
599	
600	  .page-hero {
601	    padding: 8rem 0 3.5rem;
602	  }
603	}
