/* ============================================================
   MAXIWORX 2026 — components.css
   Hamburger, Mobile-Nav, Studio-Page, allgemeine Komponenten
   ============================================================ */

/* ------------------------------------------------------------
   HAMBURGER BUTTON
   ------------------------------------------------------------ */
.hamburger {
  display: none;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  gap: 5px;
  width: 36px;
  height: 36px;
  cursor: pointer;
  background: none;
  border: none;
  padding: 4px;
  z-index: 200;
  flex-shrink: 0;
}

.hamburger__line {
  display: block;
  width: 22px;
  height: 1.5px;
  background: rgba(240, 237, 232, 0.75);
  border-radius: 2px;
  transform-origin: center;
  transition: transform 300ms ease, opacity 300ms ease, width 300ms ease;
}

/* Aktiv-Zustand: X */
.hamburger.is-open .hamburger__line:nth-child(1) {
  transform: translateY(6.5px) rotate(45deg);
}
.hamburger.is-open .hamburger__line:nth-child(2) {
  opacity: 0;
  width: 0;
}
.hamburger.is-open .hamburger__line:nth-child(3) {
  transform: translateY(-6.5px) rotate(-45deg);
}

/* ------------------------------------------------------------
   MOBILE NAV OVERLAY
   ------------------------------------------------------------ */
.mobile-nav {
  position: fixed;
  inset: 0;
  z-index: 90;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 2.5rem;

  background: rgba(6, 6, 5, 0.97);
  backdrop-filter: blur(24px);
  -webkit-backdrop-filter: blur(24px);

  opacity: 0;
  pointer-events: none;
  transform: translateY(-12px);
  transition: opacity 350ms ease, transform 350ms ease;
}

.mobile-nav.is-open {
  opacity: 1;
  pointer-events: all;
  transform: translateY(0);
}

.mobile-nav__links {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.25rem;
  list-style: none;
}

.mobile-nav__link {
  font-family: 'Cormorant Garamond', serif;
  font-size: clamp(2rem, 7vw, 3rem);
  font-weight: 300;
  letter-spacing: 0.08em;
  color: rgba(240, 237, 232, 0.55);
  transition: color 200ms ease;
  padding: 0.4rem 1rem;
  display: block;
  text-align: center;
}

.mobile-nav__link:hover {
  color: #F0EDE8;
}

.mobile-nav__link.active {
  color: #C8922A;
}

.mobile-nav__divider {
  width: 40px;
  height: 1px;
  background: rgba(200, 146, 42, 0.25);
}

.mobile-nav__cta {
  font-family: 'Inter', sans-serif;
  font-size: 0.813rem;
  font-weight: 500;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: #fff;
  background: #3A7BD5;
  border: 1px solid #3A7BD5;
  border-radius: 9999px;
  padding: 0.75rem 2.5rem;
  transition: background 200ms, box-shadow 200ms;
  margin-top: 0.5rem;
}

.mobile-nav__cta:hover {
  background: #4A8BE5;
  box-shadow: 0 4px 20px rgba(58, 123, 213, 0.35);
}

.mobile-nav__lang {
  display: flex;
  align-items: center;
  gap: 1rem;
  margin-top: 0.5rem;
}

.mobile-lang-btn {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-size: 0.75rem;
  font-weight: 500;
  letter-spacing: 0.10em;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.30);
  background: none;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 9999px;
  padding: 0.35rem 0.875rem;
  cursor: pointer;
  transition: color 200ms, border-color 200ms;
}

.mobile-lang-btn.active {
  color: #C8922A;
  border-color: rgba(200, 146, 42, 0.35);
}

.mobile-lang-btn svg {
  width: 16px;
  height: 16px;
  border-radius: 2px;
}

/* ------------------------------------------------------------
   RESPONSIVE NAV — Hamburger einblenden
   ------------------------------------------------------------ */
@media (max-width: 960px) {
  .nav-links   { display: none !important; }
  .hamburger   { display: flex; }
  .lang-switcher { display: none; } /* Im Mobile-Nav übernommen */
}

/* ------------------------------------------------------------
   PAGE HERO (Unterseiten — kein Fullscreen)
   ------------------------------------------------------------ */
.page-hero {
  position: relative;
  padding: 9rem 0 5rem;
  text-align: center;
  z-index: 10;
}

.page-hero__label {
  font-size: 0.688rem;
  font-weight: 500;
  letter-spacing: 0.28em;
  text-transform: uppercase;
  color: #C8922A;
  margin-bottom: 1rem;
  opacity: 0;
  animation: fadeUp 0.8s ease 0.2s forwards;
}

.page-hero__title {
  font-family: 'Cormorant Garamond', serif;
  font-size: clamp(3rem, 8vw, 6.5rem);
  font-weight: 300;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: #F0EDE8;
  line-height: 1.0;
  text-shadow: 0 2px 40px rgba(0, 0, 0, 0.8);
  opacity: 0;
  animation: fadeUp 1s ease 0.4s forwards;
}

.page-hero__sub {
  font-family: 'Cormorant Garamond', serif;
  font-style: italic;
  font-size: clamp(0.875rem, 2vw, 1.125rem);
  font-weight: 300;
  letter-spacing: 0.20em;
  color: rgba(200, 146, 42, 0.7);
  margin-top: 1rem;
  opacity: 0;
  animation: fadeUp 1s ease 0.6s forwards;
}

/* Gold-Linie unter Page-Hero */
.page-hero__line {
  width: 60px;
  height: 1px;
  background: linear-gradient(to right, transparent, #C8922A, transparent);
  margin: 2rem auto 0;
  opacity: 0;
  animation: fadeIn 1s ease 0.8s forwards;
}

@keyframes fadeUp { from { opacity:0; transform:translateY(16px); } to { opacity:1; transform:translateY(0); } }
@keyframes fadeIn { from { opacity:0; } to { opacity:1; } }

/* ------------------------------------------------------------
   STUDIO PAGE — Raumkarten
   ------------------------------------------------------------ */

/* Intro-Section */
.studio-intro {
  padding: 0 0 5rem;
}

.studio-intro__glass {
  background: rgba(16, 15, 13, 0.65);
  backdrop-filter: blur(24px) saturate(1.3);
  -webkit-backdrop-filter: blur(24px) saturate(1.3);
  border: 1px solid rgba(255, 255, 255, 0.07);
  border-radius: 20px;
  padding: 3rem 3.5rem;
  position: relative;
  overflow: hidden;
}

.studio-intro__glass::before {
  content: '';
  position: absolute;
  top: -80px; left: -80px;
  width: 320px; height: 320px;
  background: radial-gradient(circle, rgba(200, 146, 42, 0.06) 0%, transparent 65%);
  pointer-events: none;
}

.studio-intro__label {
  font-size: 0.688rem;
  font-weight: 500;
  letter-spacing: 0.25em;
  text-transform: uppercase;
  color: #C8922A;
  margin-bottom: 0.75rem;
}

.studio-intro__title {
  font-family: 'Cormorant Garamond', serif;
  font-size: clamp(1.5rem, 3vw, 2.25rem);
  font-weight: 300;
  color: #F0EDE8;
  line-height: 1.2;
  margin-bottom: 1.5rem;
}

.studio-intro__text {
  font-size: 0.938rem;
  font-weight: 300;
  color: rgba(168, 164, 158, 0.9);
  line-height: 1.85;
  max-width: 720px;
}

/* Raumkarten Grid */
.rooms-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 1.5rem;
  padding: 0 0 5rem;
}

.room-card {
  background: rgba(14, 14, 12, 0.70);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  border: 1px solid rgba(255, 255, 255, 0.06);
  border-radius: 16px;
  overflow: hidden;
  transition: border-color 300ms ease, box-shadow 300ms ease;
}

.room-card:hover {
  border-color: rgba(200, 146, 42, 0.22);
  box-shadow: 0 12px 40px rgba(0, 0, 0, 0.4), 0 0 0 1px rgba(200, 146, 42, 0.08);
}

/* Foto-Bereich */
.room-card__image {
  position: relative;
  aspect-ratio: 16 / 9;
  background: #0e0e0c;
  overflow: hidden;
}

.room-card__image img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  filter: brightness(0.75) saturate(0.8);
  transition: transform 600ms ease, filter 600ms ease;
}

.room-card:hover .room-card__image img {
  transform: scale(1.03);
  filter: brightness(0.85) saturate(0.9);
}

/* Platzhalter wenn kein Foto */
.room-card__placeholder {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.688rem;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.10);
}

.room-card__placeholder--a {
  background: radial-gradient(ellipse at 40% 50%, rgba(200,146,42,0.12) 0%, #0d0d0b 65%);
}
.room-card__placeholder--b {
  background: radial-gradient(ellipse at 60% 40%, rgba(58,123,213,0.10) 0%, #0d0d0b 65%);
}
.room-card__placeholder--c {
  background: radial-gradient(ellipse at 45% 55%, rgba(80,70,50,0.14) 0%, #0d0d0b 65%);
}
.room-card__placeholder--d {
  background: radial-gradient(ellipse at 55% 45%, rgba(40,60,80,0.12) 0%, #0d0d0b 65%);
}

/* Raum-Tag auf dem Foto */
.room-card__tag {
  position: absolute;
  top: 1rem;
  left: 1rem;
  font-size: 0.625rem;
  font-weight: 500;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: rgba(200, 146, 42, 0.9);
  background: rgba(8, 8, 6, 0.75);
  backdrop-filter: blur(8px);
  border: 1px solid rgba(200, 146, 42, 0.20);
  border-radius: 9999px;
  padding: 0.3rem 0.75rem;
}

/* Inhalt */
.room-card__body {
  padding: 1.75rem 2rem 2rem;
}

.room-card__title {
  font-family: 'Cormorant Garamond', serif;
  font-size: 1.375rem;
  font-weight: 400;
  color: #F0EDE8;
  margin-bottom: 0.5rem;
  line-height: 1.2;
}

.room-card__subtitle {
  font-size: 0.688rem;
  font-weight: 500;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: #C8922A;
  margin-bottom: 1.25rem;
}

.room-card__desc {
  font-size: 0.875rem;
  font-weight: 300;
  color: rgba(168, 164, 158, 0.85);
  line-height: 1.8;
  margin-bottom: 1.75rem;
}

/* Specs-Grid */
.room-specs {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 0.75rem;
  margin-bottom: 1.75rem;
}

.spec-item {
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(255, 255, 255, 0.05);
  border-radius: 8px;
  padding: 0.75rem 0.625rem;
  text-align: center;
}

.spec-item__value {
  font-family: 'Cormorant Garamond', serif;
  font-size: 1.125rem;
  font-weight: 400;
  color: #F0EDE8;
  line-height: 1.2;
  margin-bottom: 0.2rem;
}

.spec-item__label {
  font-size: 0.575rem;
  font-weight: 500;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.28);
}

/* Gear-Tags */
.room-gear {
  display: flex;
  flex-wrap: wrap;
  gap: 0.4rem;
}

.gear-tag {
  font-size: 0.625rem;
  font-weight: 400;
  letter-spacing: 0.08em;
  color: rgba(168, 164, 158, 0.65);
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(255, 255, 255, 0.07);
  border-radius: 4px;
  padding: 0.25rem 0.6rem;
  transition: color 200ms, border-color 200ms;
}

.gear-tag:hover {
  color: #C8922A;
  border-color: rgba(200, 146, 42, 0.25);
}

/* Volle Breite (für besondere Räume) */
.room-card--full {
  grid-column: span 2;
}

.room-card--full .room-card__image {
  aspect-ratio: 21 / 8;
}

.room-card--full .room-card__body {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 2.5rem;
  align-items: start;
}

.room-card--full .room-card__desc {
  margin-bottom: 0;
}

/* ------------------------------------------------------------
   BUCHUNGS-CTA SECTION
   ------------------------------------------------------------ */
.booking-cta {
  padding: 5rem 0 6rem;
}

.booking-cta__inner {
  background: rgba(16, 15, 13, 0.65);
  backdrop-filter: blur(24px) saturate(1.3);
  -webkit-backdrop-filter: blur(24px) saturate(1.3);
  border: 1px solid rgba(255, 255, 255, 0.07);
  border-radius: 20px;
  padding: 3.5rem 4rem;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 3rem;
  position: relative;
  overflow: hidden;
}

.booking-cta__inner::after {
  content: '';
  position: absolute;
  bottom: -60px; right: -60px;
  width: 280px; height: 280px;
  background: radial-gradient(circle, rgba(58, 123, 213, 0.06) 0%, transparent 65%);
  pointer-events: none;
}

.booking-cta__title {
  font-family: 'Cormorant Garamond', serif;
  font-size: clamp(1.5rem, 3vw, 2.25rem);
  font-weight: 300;
  color: #F0EDE8;
  line-height: 1.2;
  margin-bottom: 0.75rem;
}

.booking-cta__desc {
  font-size: 0.875rem;
  font-weight: 300;
  color: rgba(168, 164, 158, 0.8);
  line-height: 1.75;
  max-width: 500px;
}

.btn-cta-primary {
  display: inline-flex;
  align-items: center;
  gap: 0.6rem;
  font-family: 'Inter', sans-serif;
  font-size: 0.813rem;
  font-weight: 500;
  letter-spacing: 0.10em;
  text-transform: uppercase;
  color: #fff;
  background: #3A7BD5;
  border: 1px solid #3A7BD5;
  border-radius: 9999px;
  padding: 0.875rem 2rem;
  white-space: nowrap;
  flex-shrink: 0;
  cursor: pointer;
  transition: background 200ms, box-shadow 200ms, transform 150ms;
}

.btn-cta-primary:hover {
  background: #4A8BE5;
  box-shadow: 0 8px 28px rgba(58, 123, 213, 0.35);
  transform: translateY(-2px);
}

/* ------------------------------------------------------------
   RESPONSIVE
   ------------------------------------------------------------ */
@media (max-width: 960px) {
  .rooms-grid {
    grid-template-columns: 1fr;
  }

  .room-card--full {
    grid-column: span 1;
  }

  .room-card--full .room-card__image {
    aspect-ratio: 16 / 9;
  }

  .room-card--full .room-card__body {
    grid-template-columns: 1fr;
    gap: 1.5rem;
  }

  .booking-cta__inner {
    flex-direction: column;
    align-items: flex-start;
    padding: 2.5rem 2rem;
    gap: 2rem;
  }

  .studio-intro__glass {
    padding: 2rem 1.75rem;
  }
}

@media (max-width: 600px) {
  .room-card__body {
    padding: 1.25rem 1.25rem 1.5rem;
  }

  .room-specs {
    grid-template-columns: repeat(3, 1fr);
    gap: 0.5rem;
  }

  .page-hero {
    padding: 8rem 0 3.5rem;
  }
}

