375	/* ------------------------------------------------------------
376	   6. PARALLAX / FIXED BACKGROUND SYSTEM
377	   ------------------------------------------------------------ */
378	
379	/* Der fixierte Hintergrund bleibt an Ort und Stelle.
380	   Inhalts-Sektionen "floaten" darüber beim Scrollen. */
381	.bg-fixed-layer {
382	  position: fixed;
383	  inset: 0;
384	  z-index: var(--z-base);
385	  background-color: var(--color-bg-deep);
386	  /* Echtes Foto: background-image: url('../images/studio-bg.jpg'); */
387	  background-image:
388	    radial-gradient(ellipse 80% 60% at 50% 30%,
389	      rgba(200, 146, 42, 0.04) 0%,
390	      transparent 60%),
391	    radial-gradient(ellipse 60% 80% at 20% 80%,
392	      rgba(58, 123, 213, 0.03) 0%,
393	      transparent 50%),
394	    linear-gradient(
395	      160deg,
396	      #0A0A08 0%,
397	      #0E0E0C 25%,
398	      #101010 50%,
399	      #0C0C0A 75%,
400	      #080808 100%
401	    );
402	  background-size: cover;
403	  background-position: center top;
404	  background-attachment: fixed;
405	}
406	
407	/* Overlay für Lesbarkeit über dem Hintergrundfoto */
408	.bg-fixed-layer::after {
409	  content: '';
410	  position: absolute;
411	  inset: 0;
412	  background: var(--color-bg-overlay);
413	}
414	
415	/* Alle Sektions-Inhalte liegen über dem fixierten BG */
416	.site-content {
417	  position: relative;
418	  z-index: var(--z-above);
419	}
420	
421	/* Sektionen mit eigenem Hintergrund (Cards-Bereiche) */
422	.section--opaque {
423	  background: var(--color-bg-card);
424	}
425	
426	.section--glass {
427	  background: var(--glass-bg);
428	  backdrop-filter: var(--glass-blur);
429	  -webkit-backdrop-filter: var(--glass-blur);
430	  border-top: var(--glass-border);
431	  border-bottom: var(--glass-border);
432	}
433	
