703	  grid-row: span 2;
704	}
705	
706	/* 3-Spalten gleichmäßig */
707	.bento-grid--thirds {
708	  grid-template-columns: repeat(3, 1fr);
709	}
710	
711	/* 2 Spalten */
712	.bento-grid--halves {
713	  grid-template-columns: 1fr 1fr;
