716	/* Bento Item Basis */
717	.bento-item {
718	  position: relative;
719	  border-radius: var(--radius-lg);
720	  overflow: hidden;
721	  background: var(--color-bg-card);
722	  border: 1px solid var(--color-border);
723	  transition:
724	    border-color var(--transition-base),
725	    transform var(--transition-slow),
726	    box-shadow var(--transition-slow);
