731	  box-shadow: var(--shadow-gold);
732	}
733	
734	/* Bento mit Bild-Hintergrund */
735	.bento-item--image {
736	  aspect-ratio: 1 / 1;
737	  cursor: pointer;
738	}
739	
740	.bento-item--image .bento-image {
741	  position: absolute;
742	  inset: 0;
743	  width: 100%;
744	  height: 100%;
745	  object-fit: cover;
746	  transition: transform var(--transition-slow);
747	  filter: brightness(0.6) saturate(0.7);
748	}
749	
750	.bento-item--image:hover .bento-image {
751	  transform: scale(1.04);
752	  filter: brightness(0.75) saturate(0.85);
753	}
754	
755	.bento-item__label {
756	  position: absolute;
757	  bottom: var(--space-5);
758	  left: var(--space-5);
759	  right: var(--space-5);
760	}
