1027	.site-footer {
1028	  position: relative;
1029	  z-index: var(--z-above);
1030	  background: #050505;
1031	  border-top: 1px solid var(--color-border);
1032	  padding: var(--space-8) 0;
1033	}
1034	
1035	.footer-inner {
1036	  max-width: var(--container-max);
1037	  margin-inline: auto;
1038	  padding-inline: var(--space-6);
1039	  display: flex;
1040	  align-items: center;
1041	  justify-content: space-between;
1042	  flex-wrap: wrap;
1043	  gap: var(--space-6);
1044	}
1045	
1046	.footer-logo {
1047	  font-family: var(--font-display);
1048	  font-size: 1rem;
1049	  letter-spacing: 0.15em;
1050	  text-transform: uppercase;
1051	  color: var(--color-text-muted);
1052	  transition: color var(--transition-fast);
1053	}
1054	
1055	.footer-logo:hover {
1056	  color: var(--color-text-primary);
1057	}
1058	
1059	.footer-links {
1060	  display: flex;
1061	  align-items: center;
1062	  gap: var(--space-6);
1063	  flex-wrap: wrap;
1064	}
1065	
1066	.footer-link {
1067	  font-size: var(--text-xs);
1068	  font-weight: var(--weight-medium);
1069	  letter-spacing: 0.10em;
1070	  text-transform: uppercase;
1071	  color: var(--color-text-muted);
1072	  transition: color var(--transition-fast);
1073	}
1074	
1075	.footer-link:hover {
1076	  color: var(--color-gold);
1077	}
1078	
1079	.footer-social {
1080	  display: flex;
1081	  align-items: center;
1082	  gap: var(--space-4);
1083	}
1084	
1085	.footer-social-link {
1086	  width: 32px;
1087	  height: 32px;
1088	  display: flex;
1089	  align-items: center;
1090	  justify-content: center;
1091	  border-radius: var(--radius-full);
1092	  border: 1px solid var(--color-border);
1093	  color: var(--color-text-muted);
1094	  transition:
1095	    color var(--transition-fast),
1096	    border-color var(--transition-fast),
1097	    box-shadow var(--transition-fast);
1098	}
1099	
1100	.footer-social-link:hover {
1101	  color: var(--color-gold);
1102	  border-color: var(--color-border-gold);
1103	  box-shadow: var(--shadow-gold);
1104	}
1105	
1106	.footer-copy {
1107	  width: 100%;
1108	  padding-top: var(--space-6);
1109	  border-top: 1px solid var(--color-border);
1110	  display: flex;
1111	  align-items: center;
1112	  justify-content: center;
1113	  font-size: var(--text-xs);
1114	  letter-spacing: 0.15em;
1115	  text-transform: uppercase;
1116	  color: var(--color-text-muted);
1117	}
1118	
1119	
1120	/* ------------------------------------------------------------
1121	   15. SCROLL-ANIMATION STATES
1122	   (GSAP setzt diese Klassen, CSS definiert die Zustände)
1123	   ------------------------------------------------------------ */
1124	
1125	/* Elemente die noch nicht sichtbar sind (initial state) */
1126	.reveal-up {
1127	  opacity: 0;
1128	  transform: translateY(30px);
1129	}
1130	
1131	.reveal-fade {
1132	  opacity: 0;
1133	}
1134	
1135	.reveal-left {
1136	  opacity: 0;
1137	  transform: translateX(-30px);
1138	}
1139	
1140	.reveal-right {
1141	  opacity: 0;
1142	  transform: translateX(30px);
1143	}
1144	
1145	/* GSAP animiert zu diesen Zuständen */
1146	.revealed {
1147	  opacity: 1;
1148	  transform: translateY(0) translateX(0);
1149	}
1150	
1151	
1152	/* ------------------------------------------------------------
1153	   16. UTILITY KLASSEN
1154	   ------------------------------------------------------------ */
1155	.visually-hidden {
1156	  position: absolute;
1157	  width: 1px;
1158	  height: 1px;
1159	  padding: 0;
1160	  margin: -1px;
1161	  overflow: hidden;
1162	  clip: rect(0, 0, 0, 0);
1163	  white-space: nowrap;
1164	  border: 0;
1165	}
1166	
1167	.text-center  { text-align: center; }
1168	.text-right   { text-align: right; }
1169	
1170	.mt-auto { margin-top: auto; }
1171	.ml-auto { margin-left: auto; }
1172	
1173	.w-full  { width: 100%; }
1174	.h-full  { height: 100%; }
1175	
1176	/* Aspect Ratios */
1177	.aspect-square  { aspect-ratio: 1 / 1; }
1178	.aspect-video   { aspect-ratio: 16 / 9; }
1179	.aspect-photo   { aspect-ratio: 4 / 3; }
1180	
1181	/* Overflow */
1182	.overflow-hidden  { overflow: hidden; }
1183	.overflow-clip    { overflow: clip; }
1184	
1185	
1186	/* ------------------------------------------------------------
1187	   17. RESPONSIVE BREAKPOINTS
1188	   ------------------------------------------------------------ */
1189	
1190	/* Tablet */
1191	@media (max-width: 1024px) {
1192	  :root {
1193	    --space-24: 5rem;
1194	    --space-32: 6rem;
1195	  }
1196	
1197	  .bento-grid--references {
1198	    grid-template-columns: 1fr;
1199	  }
1200	
1201	  .bento-grid--references .bento-item:first-child {
1202	    grid-row: span 1;
1203	  }
1204	
1205	  .nav-links {
1206	    gap: var(--space-4);
1207	  }
1208	}
1209	
1210	/* Mobile */
1211	@media (max-width: 768px) {
1212	  :root {
1213	    --container-max: 100%;
1214	    --space-24: 4rem;
1215	    --bento-gap: 10px;
1216	  }
1217	
1218	  .bento-grid--thirds {
1219	    grid-template-columns: 1fr;
1220	  }
1221	
1222	  .bento-grid--halves {
1223	    grid-template-columns: 1fr;
1224	  }
1225	
1226	  .footer-inner {
1227	    flex-direction: column;
1228	    align-items: flex-start;
1229	  }
1230	
1231	  /* Mobile Nav — Links ausgeblendet, Hamburger zeigen */
1232	  .nav-links {
1233	    display: none;
1234	  }
1235	
1236	  .nav-links.mobile-open {
1237	    display: flex;
1238	    flex-direction: column;
1239	    position: fixed;
1240	    inset: 0;
1241	    padding-top: var(--nav-height);
1242	    background: rgba(8, 8, 8, 0.98);
1243	    backdrop-filter: blur(20px);
1244	    z-index: calc(var(--z-nav) - 1);
1245	    align-items: center;
1246	    justify-content: center;
1247	    gap: var(--space-8);
1248	  }
1249	
1250	  .mobile-open .nav-link {
1251	    font-size: var(--text-xl);
1252	    letter-spacing: 0.08em;
1253	  }
1254	}
1255	
1256	
1257	/* ------------------------------------------------------------
1258	   18. REDUCED MOTION
1259	   ------------------------------------------------------------ */
1260	@media (prefers-reduced-motion: reduce) {
1261	  *, *::before, *::after {
1262	    animation-duration: 0.01ms !important;
1263	    animation-iteration-count: 1 !important;
1264	    transition-duration: 0.01ms !important;
1265	  }
1266	
1267	  .hero-scroll-hint {
1268	    animation: none;
1269	  }
1270	
1271	  html {
1272	    scroll-behavior: auto;
1273	  }
1274	}
