/* ============================================================
   MAXIWORX 2026 — Design System
   "Where Nature Distills High-End Tech"

   Autor:    Lead Developer
   Stack:    Vanilla CSS, XAMPP/Apache, PHP 8.5+
   Version:  1.0.0
   ============================================================ */

/* ------------------------------------------------------------
   1. GOOGLE FONTS IMPORT
   ------------------------------------------------------------ */
@import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;0,600;1,300;1,400;1,500&family=Inter:wght@300;400;500;600&family=Cormorant:ital,wght@0,300;1,300&display=swap');


/* ------------------------------------------------------------
   2. CSS CUSTOM PROPERTIES (Design Tokens)
   ------------------------------------------------------------ */
:root {

  /* --- Farben: Basis --- */
  --color-bg-base:        #080808;   /* Tiefstes Schwarz — Haupt-Hintergrund */
  --color-bg-deep:        #0D0D0D;   /* Hintergrund fixiert (parallax layer) */
  --color-bg-card:        #141414;   /* Cards, Sektionen */
  --color-bg-card-hover:  #1C1C1C;   /* Card hover state */
  --color-bg-surface:     #1A1A1A;   /* Surfaces, modals */
  --color-bg-input:       #111111;   /* Formularfelder */
  --color-bg-overlay:     rgba(8, 8, 8, 0.75); /* Overlay über Hintergrundbild */

  /* --- Farben: Text --- */
  --color-text-primary:   #F0EDE8;   /* Headlines — warmes Weiß */
  --color-text-secondary: #A8A49E;   /* Subheadlines, Labels */
  --color-text-muted:     #5C5955;   /* Muted text, Metadaten */
  --color-text-inverse:   #0A0A0A;   /* Text auf hellen Flächen */

  /* --- Farben: Akzent Gold (Kern-Identität) --- */
  --color-gold:           #C8922A;   /* Primärer Gold-Akzent */
  --color-gold-light:     #D4A843;   /* Hover, highlights */
  --color-gold-dim:       #8A6420;   /* Subtle gold (borders, dividers) */
  --color-gold-glow:      rgba(200, 146, 42, 0.15); /* Gold glow effect */
  --color-gold-glow-strong: rgba(200, 146, 42, 0.30);

  /* --- Farben: Blau (Tech-Akzent, nur CTA) --- */
  --color-blue:           #3A7BD5;   /* CTA Button */
  --color-blue-hover:     #4A8BE5;
  --color-blue-glow:      rgba(58, 123, 213, 0.20);

  /* --- Farben: Borders --- */
  --color-border:         rgba(255, 255, 255, 0.06);
  --color-border-hover:   rgba(255, 255, 255, 0.12);
  --color-border-gold:    rgba(200, 146, 42, 0.25);
  --color-border-gold-strong: rgba(200, 146, 42, 0.50);

  /* --- Glassmorphism --- */
  --glass-bg:             rgba(20, 20, 20, 0.60);
  --glass-bg-light:       rgba(30, 30, 30, 0.40);
  --glass-blur:           blur(20px);
  --glass-blur-heavy:     blur(40px);
  --glass-border:         1px solid rgba(255, 255, 255, 0.08);
  --glass-border-gold:    1px solid rgba(200, 146, 42, 0.20);

  /* --- Typografie: Familien --- */
  --font-display:   'Cormorant Garamond', 'Georgia', serif;   /* Headlines, Logo */
  --font-body:      'Inter', 'Helvetica Neue', sans-serif;    /* UI, Body-Text */
  --font-caption:   'Cormorant', 'Georgia', serif;            /* Kursiv-Captions */

  /* --- Typografie: Größen (fluid clamp-basiert) --- */
  --text-xs:        0.688rem;   /* 11px */
  --text-sm:        0.813rem;   /* 13px */
  --text-base:      0.938rem;   /* 15px */
  --text-md:        1.063rem;   /* 17px */
  --text-lg:        1.25rem;    /* 20px */
  --text-xl:        1.5rem;     /* 24px */
  --text-2xl:       2rem;       /* 32px */
  --text-3xl:       clamp(2.5rem, 5vw, 4rem);      /* ~40-64px */
  --text-4xl:       clamp(3.5rem, 7vw, 6rem);      /* ~56-96px */
  --text-hero:      clamp(4rem,  10vw, 8.5rem);    /* Hero-Titel */

  /* --- Typografie: Gewichte --- */
  --weight-light:   300;
  --weight-regular: 400;
  --weight-medium:  500;
  --weight-semibold:600;

  /* --- Spacing --- */
  --space-1:  0.25rem;   /*  4px */
  --space-2:  0.5rem;    /*  8px */
  --space-3:  0.75rem;   /* 12px */
  --space-4:  1rem;      /* 16px */
  --space-5:  1.25rem;   /* 20px */
  --space-6:  1.5rem;    /* 24px */
  --space-8:  2rem;      /* 32px */
  --space-10: 2.5rem;    /* 40px */
  --space-12: 3rem;      /* 48px */
  --space-16: 4rem;      /* 64px */
  --space-20: 5rem;      /* 80px */
  --space-24: 6rem;      /* 96px */
  --space-32: 8rem;      /* 128px */

  /* --- Border Radius --- */
  --radius-sm:   4px;
  --radius-md:   8px;
  --radius-lg:   12px;
  --radius-xl:   20px;
  --radius-full: 9999px;

  /* --- Shadows --- */
  --shadow-sm:    0 1px 3px rgba(0,0,0,0.40);
  --shadow-md:    0 4px 16px rgba(0,0,0,0.50);
  --shadow-lg:    0 8px 32px rgba(0,0,0,0.60);
  --shadow-xl:    0 16px 64px rgba(0,0,0,0.70);
  --shadow-gold:  0 4px 24px rgba(200, 146, 42, 0.20);
  --shadow-gold-strong: 0 8px 40px rgba(200, 146, 42, 0.35);

  /* --- Transitions --- */
  --transition-fast:   150ms cubic-bezier(0.4, 0, 0.2, 1);
  --transition-base:   250ms cubic-bezier(0.4, 0, 0.2, 1);
  --transition-slow:   400ms cubic-bezier(0.4, 0, 0.2, 1);
  --transition-spring: 500ms cubic-bezier(0.34, 1.56, 0.64, 1);

  /* --- Layout --- */
  --container-max:   1280px;
  --container-wide:  1440px;
  --nav-height:      64px;
  --nav-height-scrolled: 52px;

  /* --- Z-Index Skala --- */
  --z-base:     0;
  --z-above:    10;
  --z-overlay:  20;
  --z-modal:    30;
  --z-nav:      40;
  --z-toast:    50;

  /* --- Bento Grid --- */
  --bento-gap:  16px;
  --bento-gap-sm: 10px;
}


/* ------------------------------------------------------------
   3. CSS RESET & BASE
   ------------------------------------------------------------ */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  scroll-behavior: smooth;
  font-size: 16px;
  -webkit-text-size-adjust: 100%;
  text-size-adjust: 100%;
}

body {
  background-color: var(--color-bg-base);
  color: var(--color-text-primary);
  font-family: var(--font-body);
  font-size: var(--text-base);
  font-weight: var(--weight-regular);
  line-height: 1.6;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  overflow-x: hidden;
}

img, video {
  display: block;
  max-width: 100%;
  height: auto;
}

a {
  color: inherit;
  text-decoration: none;
}

button {
  cursor: pointer;
  border: none;
  background: none;
  font-family: inherit;
}

input, textarea, select {
  font-family: inherit;
  font-size: inherit;
  color: inherit;
}

ul, ol {
  list-style: none;
}

::selection {
  background: var(--color-gold-glow-strong);
  color: var(--color-gold-light);
}

/* Scrollbar Styling */
::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}
::-webkit-scrollbar-track {
  background: var(--color-bg-base);
}
::-webkit-scrollbar-thumb {
  background: var(--color-gold-dim);
  border-radius: var(--radius-full);
}
::-webkit-scrollbar-thumb:hover {
  background: var(--color-gold);
}


/* ------------------------------------------------------------
   4. TYPOGRAFIE-SYSTEM
   ------------------------------------------------------------ */

/* Display / Hero */
.t-hero {
  font-family: var(--font-display);
  font-size: var(--text-hero);
  font-weight: var(--weight-light);
  letter-spacing: 0.15em;
  text-transform: uppercase;
  line-height: 1.0;
  color: var(--color-text-primary);
}

.t-display {
  font-family: var(--font-display);
  font-size: var(--text-4xl);
  font-weight: var(--weight-light);
  letter-spacing: 0.04em;
  line-height: 1.1;
  color: var(--color-text-primary);
}

.t-heading {
  font-family: var(--font-display);
  font-size: var(--text-3xl);
  font-weight: var(--weight-light);
  letter-spacing: 0.02em;
  line-height: 1.15;
  color: var(--color-text-primary);
}

.t-subheading {
  font-family: var(--font-display);
  font-size: var(--text-xl);
  font-weight: var(--weight-regular);
  letter-spacing: 0.01em;
  line-height: 1.3;
  color: var(--color-text-primary);
}

/* Tagline (kursiv, gold) */
.t-tagline {
  font-family: var(--font-display);
  font-style: italic;
  font-size: clamp(0.875rem, 2vw, 1.125rem);
  font-weight: var(--weight-light);
  letter-spacing: 0.25em;
  text-transform: uppercase;
  color: var(--color-gold);
  line-height: 1.4;
}

/* Label / Overline (Kategorie-Labels, z.B. "PORTFOLIO") */
.t-label {
  font-family: var(--font-body);
  font-size: var(--text-xs);
  font-weight: var(--weight-medium);
  letter-spacing: 0.20em;
  text-transform: uppercase;
  color: var(--color-gold);
  line-height: 1.4;
}

/* Body Text */
.t-body {
  font-family: var(--font-body);
  font-size: var(--text-base);
  font-weight: var(--weight-light);
  line-height: 1.75;
  color: var(--color-text-secondary);
}

.t-body-sm {
  font-family: var(--font-body);
  font-size: var(--text-sm);
  font-weight: var(--weight-light);
  line-height: 1.65;
  color: var(--color-text-secondary);
}

/* Nav Text */
.t-nav {
  font-family: var(--font-body);
  font-size: var(--text-sm);
  font-weight: var(--weight-medium);
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--color-text-secondary);
}

/* Caption (kursiv serif) */
.t-caption {
  font-family: var(--font-caption);
  font-style: italic;
  font-size: var(--text-sm);
  font-weight: var(--weight-light);
  color: var(--color-text-muted);
  letter-spacing: 0.02em;
}

/* Muted */
.t-muted {
  color: var(--color-text-muted);
}

/* Gold highlight */
.t-gold {
  color: var(--color-gold);
}


/* ------------------------------------------------------------
   5. LAYOUT UTILITIES
   ------------------------------------------------------------ */
.container {
  width: 100%;
  max-width: var(--container-max);
  margin-inline: auto;
  padding-inline: var(--space-6);
}

.container--wide {
  max-width: var(--container-wide);
  padding-inline: var(--space-8);
}

.container--narrow {
  max-width: 860px;
}

/* Section Padding */
.section {
  padding-block: var(--space-24);
  position: relative;
}

.section--lg {
  padding-block: var(--space-32);
}

.section--sm {
  padding-block: var(--space-16);
}

/* Flex helpers */
.flex       { display: flex; }
.flex-col   { flex-direction: column; }
.items-center { align-items: center; }
.justify-between { justify-content: space-between; }
.gap-4      { gap: var(--space-4); }
.gap-6      { gap: var(--space-6); }
.gap-8      { gap: var(--space-8); }


/* ------------------------------------------------------------
   6. PARALLAX / FIXED BACKGROUND SYSTEM
   ------------------------------------------------------------ */

/* Der fixierte Hintergrund bleibt an Ort und Stelle.
   Inhalts-Sektionen "floaten" darüber beim Scrollen. */
.bg-fixed-layer {
  position: fixed;
  inset: 0;
  z-index: var(--z-base);
  background-color: var(--color-bg-deep);
  /* Echtes Foto: background-image: url('../images/studio-bg.jpg'); */
  background-image:
    radial-gradient(ellipse 80% 60% at 50% 30%,
      rgba(200, 146, 42, 0.04) 0%,
      transparent 60%),
    radial-gradient(ellipse 60% 80% at 20% 80%,
      rgba(58, 123, 213, 0.03) 0%,
      transparent 50%),
    linear-gradient(
      160deg,
      #0A0A08 0%,
      #0E0E0C 25%,
      #101010 50%,
      #0C0C0A 75%,
      #080808 100%
    );
  background-size: cover;
  background-position: center top;
  background-attachment: fixed;
}

/* Overlay für Lesbarkeit über dem Hintergrundfoto */
.bg-fixed-layer::after {
  content: '';
  position: absolute;
  inset: 0;
  background: var(--color-bg-overlay);
}

/* Alle Sektions-Inhalte liegen über dem fixierten BG */
.site-content {
  position: relative;
  z-index: var(--z-above);
}

/* Sektionen mit eigenem Hintergrund (Cards-Bereiche) */
.section--opaque {
  background: var(--color-bg-card);
}

.section--glass {
  background: var(--glass-bg);
  backdrop-filter: var(--glass-blur);
  -webkit-backdrop-filter: var(--glass-blur);
  border-top: var(--glass-border);
  border-bottom: var(--glass-border);
}


/* ------------------------------------------------------------
   7. NAVIGATION
   ------------------------------------------------------------ */
.site-nav {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  z-index: var(--z-nav);
  height: var(--nav-height);
  display: flex;
  align-items: center;
  transition: height var(--transition-slow),
              background var(--transition-slow),
              backdrop-filter var(--transition-slow);
}

/* Transparente Nav im Hero-Bereich */
.site-nav--transparent {
  background: transparent;
}

/* Verglaste Nav beim Scrollen */
.site-nav--scrolled {
  height: var(--nav-height-scrolled);
  background: rgba(8, 8, 8, 0.85);
  backdrop-filter: var(--glass-blur-heavy);
  -webkit-backdrop-filter: var(--glass-blur-heavy);
  border-bottom: 1px solid var(--color-border);
}

.nav-inner {
  width: 100%;
  max-width: var(--container-max);
  margin-inline: auto;
  padding-inline: var(--space-6);
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-8);
}

/* Logo */
.nav-logo {
  font-family: var(--font-display);
  font-size: 1.25rem;
  font-weight: var(--weight-medium);
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--color-text-primary);
  white-space: nowrap;
  transition: opacity var(--transition-base);
}

/* Nav-Titel-Integration (erscheint beim Scrollen) */
.nav-hero-title {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  overflow: hidden;
  max-height: 0;
  opacity: 0;
  transition:
    max-height var(--transition-slow),
    opacity var(--transition-slow);
}

.site-nav--scrolled .nav-hero-title {
  max-height: 40px;
  opacity: 1;
}

.nav-hero-title .title {
  font-family: var(--font-display);
  font-size: var(--text-xs);
  font-weight: var(--weight-medium);
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--color-text-primary);
  line-height: 1.2;
}

.nav-hero-title .tagline {
  font-family: var(--font-display);
  font-style: italic;
  font-size: 0.625rem;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--color-gold);
  line-height: 1.2;
}

/* Nav Links */
.nav-links {
  display: flex;
  align-items: center;
  gap: var(--space-6);
}

.nav-link {
  font-family: var(--font-body);
  font-size: var(--text-xs);
  font-weight: var(--weight-medium);
  letter-spacing: 0.10em;
  text-transform: uppercase;
  color: var(--color-text-secondary);
  transition: color var(--transition-fast);
  position: relative;
  padding-block: var(--space-1);
}

.nav-link::after {
  content: '';
  position: absolute;
  bottom: -2px;
  left: 0;
  width: 0;
  height: 1px;
  background: var(--color-gold);
  transition: width var(--transition-base);
}

.nav-link:hover {
  color: var(--color-text-primary);
}

.nav-link:hover::after,
.nav-link.active::after {
  width: 100%;
}

.nav-link.active {
  color: var(--color-text-primary);
}

/* CTA Button */
.btn-nav-cta {
  font-family: var(--font-body);
  font-size: var(--text-xs);
  font-weight: var(--weight-medium);
  letter-spacing: 0.10em;
  text-transform: uppercase;
  color: #ffffff;
  background: var(--color-blue);
  border: 1px solid var(--color-blue);
  border-radius: var(--radius-full);
  padding: var(--space-2) var(--space-5);
  transition:
    background var(--transition-fast),
    box-shadow var(--transition-fast),
    transform var(--transition-fast);
  white-space: nowrap;
}

.btn-nav-cta:hover {
  background: var(--color-blue-hover);
  box-shadow: var(--color-blue-glow) 0 4px 20px;
  transform: translateY(-1px);
}

.btn-nav-cta:active {
  transform: translateY(0);
}


/* ------------------------------------------------------------
   8. HERO SECTION
   ------------------------------------------------------------ */
.hero {
  position: relative;
  min-height: 100svh;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
  padding-top: var(--nav-height);
  overflow: hidden;
}

.hero-content {
  position: relative;
  z-index: 2;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--space-5);
}

/* Der Haupt-Titel — transformiert sich beim Scrollen */
.hero-title-wrap {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--space-4);
  will-change: transform, opacity;
}

.hero-title {
  font-family: var(--font-display);
  font-size: var(--text-hero);
  font-weight: var(--weight-light);
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--color-text-primary);
  line-height: 0.95;
  text-shadow: 0 2px 40px rgba(0,0,0,0.8);
}

.hero-tagline {
  font-family: var(--font-display);
  font-style: italic;
  font-size: clamp(0.75rem, 1.5vw, 1rem);
  font-weight: var(--weight-light);
  letter-spacing: 0.30em;
  text-transform: uppercase;
  color: var(--color-gold);
  text-shadow: 0 0 30px var(--color-gold-glow);
}

/* Scroll-Indikator */
.hero-scroll-hint {
  position: absolute;
  bottom: var(--space-8);
  left: 50%;
  transform: translateX(-50%);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--space-2);
  opacity: 0.5;
  animation: scrollBounce 2s ease-in-out infinite;
}

.hero-scroll-hint span {
  font-size: var(--text-xs);
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--color-text-muted);
}

.scroll-line {
  width: 1px;
  height: 40px;
  background: linear-gradient(to bottom, var(--color-gold-dim), transparent);
}

@keyframes scrollBounce {
  0%, 100% { transform: translateX(-50%) translateY(0); }
  50%       { transform: translateX(-50%) translateY(8px); }
}


/* ------------------------------------------------------------
   9. BENTO GRID SYSTEM
   ------------------------------------------------------------ */
.bento-grid {
  display: grid;
  gap: var(--bento-gap);
}

/* Referenzen Grid (1 groß links, 2×2 rechts) */
.bento-grid--references {
  grid-template-columns: 1fr 1fr;
  grid-template-rows: auto;
}

.bento-grid--references .bento-item:first-child {
  grid-row: span 2;
}

/* 3-Spalten gleichmäßig */
.bento-grid--thirds {
  grid-template-columns: repeat(3, 1fr);
}

/* 2 Spalten */
.bento-grid--halves {
  grid-template-columns: 1fr 1fr;
}

/* Bento Item Basis */
.bento-item {
  position: relative;
  border-radius: var(--radius-lg);
  overflow: hidden;
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  transition:
    border-color var(--transition-base),
    transform var(--transition-slow),
    box-shadow var(--transition-slow);
}

.bento-item:hover {
  border-color: var(--color-border-gold);
  box-shadow: var(--shadow-gold);
}

/* Bento mit Bild-Hintergrund */
.bento-item--image {
  aspect-ratio: 1 / 1;
  cursor: pointer;
}

.bento-item--image .bento-image {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform var(--transition-slow);
  filter: brightness(0.6) saturate(0.7);
}

.bento-item--image:hover .bento-image {
  transform: scale(1.04);
  filter: brightness(0.75) saturate(0.85);
}

.bento-item__label {
  position: absolute;
  bottom: var(--space-5);
  left: var(--space-5);
  right: var(--space-5);
}

/* Bento Text-Card */
.bento-item--text {
  padding: var(--space-8);
  display: flex;
  flex-direction: column;
  gap: var(--space-4);
}


/* ------------------------------------------------------------
   10. CARDS & SURFACES
   ------------------------------------------------------------ */

/* Standard Card */
.card {
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  padding: var(--space-8);
  transition:
    border-color var(--transition-base),
    background var(--transition-base),
    box-shadow var(--transition-base);
}

.card:hover {
  border-color: var(--color-border-hover);
  background: var(--color-bg-card-hover);
}

/* Glas-Card */
.card--glass {
  background: var(--glass-bg);
  backdrop-filter: var(--glass-blur);
  -webkit-backdrop-filter: var(--glass-blur);
  border: var(--glass-border);
}

.card--glass:hover {
  background: var(--glass-bg-light);
  border: var(--glass-border-gold);
  box-shadow: var(--shadow-gold);
}

/* Gold-Akzent Card */
.card--gold {
  border-color: var(--color-border-gold);
}

.card--gold:hover {
  border-color: var(--color-border-gold-strong);
  box-shadow: var(--shadow-gold-strong);
}

/* Feature Card (Beyond the Booth) */
.feature-card {
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  padding: var(--space-8) var(--space-6);
  display: flex;
  flex-direction: column;
  gap: var(--space-5);
  transition:
    border-color var(--transition-base),
    box-shadow var(--transition-base);
}

.feature-card:hover {
  border-color: var(--color-border-gold);
  box-shadow: var(--shadow-gold);
}

.feature-card__icon {
  width: 40px;
  height: 40px;
  color: var(--color-gold);
  opacity: 0.85;
}

.feature-card__divider {
  width: 40px;
  height: 1px;
  background: var(--color-gold-dim);
  transition: width var(--transition-slow);
}

.feature-card:hover .feature-card__divider {
  width: 80px;
}


/* ------------------------------------------------------------
   11. BUTTONS
   ------------------------------------------------------------ */

/* Primär (blau, CTA) */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-2);
  font-family: var(--font-body);
  font-size: var(--text-sm);
  font-weight: var(--weight-medium);
  letter-spacing: 0.08em;
  text-transform: uppercase;
  border-radius: var(--radius-full);
  padding: var(--space-3) var(--space-8);
  transition:
    background var(--transition-fast),
    transform var(--transition-fast),
    box-shadow var(--transition-fast);
  white-space: nowrap;
  cursor: pointer;
}

.btn--primary {
  background: var(--color-blue);
  color: #ffffff;
  border: 1px solid var(--color-blue);
}

.btn--primary:hover {
  background: var(--color-blue-hover);
  box-shadow: 0 8px 30px var(--color-blue-glow);
  transform: translateY(-2px);
}

/* Ghost (transparenter Rand) */
.btn--ghost {
  background: transparent;
  color: var(--color-text-secondary);
  border: 1px solid var(--color-border-hover);
}

.btn--ghost:hover {
  color: var(--color-text-primary);
  border-color: var(--color-border-gold);
  box-shadow: var(--shadow-gold);
}

/* Gold-Outline */
.btn--gold {
  background: transparent;
  color: var(--color-gold);
  border: 1px solid var(--color-border-gold-strong);
}

.btn--gold:hover {
  background: var(--color-gold-glow);
  box-shadow: var(--shadow-gold);
  transform: translateY(-2px);
}

/* Text-Link mit Pfeil */
.btn--link {
  background: transparent;
  border: none;
  color: var(--color-text-secondary);
  padding: 0;
  font-size: var(--text-sm);
  letter-spacing: 0.06em;
  text-transform: uppercase;
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  transition: color var(--transition-fast), gap var(--transition-fast);
}

.btn--link:hover {
  color: var(--color-text-primary);
  gap: var(--space-4);
}

.btn--link .arrow {
  transition: transform var(--transition-fast);
}

.btn--link:hover .arrow {
  transform: translateX(4px);
}


/* ------------------------------------------------------------
   12. FORMULAR-ELEMENTE
   ------------------------------------------------------------ */
.form-group {
  display: flex;
  flex-direction: column;
  gap: var(--space-2);
}

.form-label {
  font-size: var(--text-xs);
  font-weight: var(--weight-medium);
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--color-text-muted);
}

.form-input {
  background: var(--color-bg-input);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  padding: var(--space-3) var(--space-4);
  font-size: var(--text-sm);
  color: var(--color-text-primary);
  transition:
    border-color var(--transition-fast),
    box-shadow var(--transition-fast);
  outline: none;
  width: 100%;
}

.form-input::placeholder {
  color: var(--color-text-muted);
}

.form-input:focus {
  border-color: var(--color-border-gold);
  box-shadow: 0 0 0 3px var(--color-gold-glow);
}

.form-input:hover:not(:focus) {
  border-color: var(--color-border-hover);
}


/* ------------------------------------------------------------
   13. DIVIDER & DEKORATION
   ------------------------------------------------------------ */

/* Gold-Divider */
.divider-gold {
  width: 60px;
  height: 1px;
  background: linear-gradient(to right, var(--color-gold), transparent);
}

.divider-gold--center {
  margin-inline: auto;
  background: linear-gradient(to right, transparent, var(--color-gold), transparent);
  width: 120px;
}

/* Section Eyebrow (Label + Line) */
.section-eyebrow {
  display: flex;
  align-items: center;
  gap: var(--space-4);
  margin-bottom: var(--space-4);
}

.section-eyebrow::before {
  content: '';
  width: 24px;
  height: 1px;
  background: var(--color-gold);
}


/* ------------------------------------------------------------
   14. FOOTER
   ------------------------------------------------------------ */
.site-footer {
  position: relative;
  z-index: var(--z-above);
  background: #050505;
  border-top: 1px solid var(--color-border);
  padding: var(--space-8) 0;
}

.footer-inner {
  max-width: var(--container-max);
  margin-inline: auto;
  padding-inline: var(--space-6);
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: var(--space-6);
}

.footer-logo {
  font-family: var(--font-display);
  font-size: 1rem;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--color-text-muted);
  transition: color var(--transition-fast);
}

.footer-logo:hover {
  color: var(--color-text-primary);
}

.footer-links {
  display: flex;
  align-items: center;
  gap: var(--space-6);
  flex-wrap: wrap;
}

.footer-link {
  font-size: var(--text-xs);
  font-weight: var(--weight-medium);
  letter-spacing: 0.10em;
  text-transform: uppercase;
  color: var(--color-text-muted);
  transition: color var(--transition-fast);
}

.footer-link:hover {
  color: var(--color-gold);
}

.footer-social {
  display: flex;
  align-items: center;
  gap: var(--space-4);
}

.footer-social-link {
  width: 32px;
  height: 32px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: var(--radius-full);
  border: 1px solid var(--color-border);
  color: var(--color-text-muted);
  transition:
    color var(--transition-fast),
    border-color var(--transition-fast),
    box-shadow var(--transition-fast);
}

.footer-social-link:hover {
  color: var(--color-gold);
  border-color: var(--color-border-gold);
  box-shadow: var(--shadow-gold);
}

.footer-copy {
  width: 100%;
  padding-top: var(--space-6);
  border-top: 1px solid var(--color-border);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: var(--text-xs);
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--color-text-muted);
}


/* ------------------------------------------------------------
   15. SCROLL-ANIMATION STATES
   (GSAP setzt diese Klassen, CSS definiert die Zustände)
   ------------------------------------------------------------ */

/* Elemente die noch nicht sichtbar sind (initial state) */
.reveal-up {
  opacity: 0;
  transform: translateY(30px);
}

.reveal-fade {
  opacity: 0;
}

.reveal-left {
  opacity: 0;
  transform: translateX(-30px);
}

.reveal-right {
  opacity: 0;
  transform: translateX(30px);
}

/* GSAP animiert zu diesen Zuständen */
.revealed {
  opacity: 1;
  transform: translateY(0) translateX(0);
}


/* ------------------------------------------------------------
   16. UTILITY KLASSEN
   ------------------------------------------------------------ */
.visually-hidden {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

.text-center  { text-align: center; }
.text-right   { text-align: right; }

.mt-auto { margin-top: auto; }
.ml-auto { margin-left: auto; }

.w-full  { width: 100%; }
.h-full  { height: 100%; }

/* Aspect Ratios */
.aspect-square  { aspect-ratio: 1 / 1; }
.aspect-video   { aspect-ratio: 16 / 9; }
.aspect-photo   { aspect-ratio: 4 / 3; }

/* Overflow */
.overflow-hidden  { overflow: hidden; }
.overflow-clip    { overflow: clip; }


/* ------------------------------------------------------------
   17. RESPONSIVE BREAKPOINTS
   ------------------------------------------------------------ */

/* Tablet */
@media (max-width: 1024px) {
  :root {
    --space-24: 5rem;
    --space-32: 6rem;
  }

  .bento-grid--references {
    grid-template-columns: 1fr;
  }

  .bento-grid--references .bento-item:first-child {
    grid-row: span 1;
  }

  .nav-links {
    gap: var(--space-4);
  }
}

/* Mobile */
@media (max-width: 768px) {
  :root {
    --container-max: 100%;
    --space-24: 4rem;
    --bento-gap: 10px;
  }

  .bento-grid--thirds {
    grid-template-columns: 1fr;
  }

  .bento-grid--halves {
    grid-template-columns: 1fr;
  }

  .footer-inner {
    flex-direction: column;
    align-items: flex-start;
  }

  /* Mobile Nav — Links ausgeblendet, Hamburger zeigen */
  .nav-links {
    display: none;
  }

  .nav-links.mobile-open {
    display: flex;
    flex-direction: column;
    position: fixed;
    inset: 0;
    padding-top: var(--nav-height);
    background: rgba(8, 8, 8, 0.98);
    backdrop-filter: blur(20px);
    z-index: calc(var(--z-nav) - 1);
    align-items: center;
    justify-content: center;
    gap: var(--space-8);
  }

  .mobile-open .nav-link {
    font-size: var(--text-xl);
    letter-spacing: 0.08em;
  }
}


/* ------------------------------------------------------------
   18. REDUCED MOTION
   ------------------------------------------------------------ */
@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }

  .hero-scroll-hint {
    animation: none;
  }

  html {
    scroll-behavior: auto;
  }
}

