1	/**
2	 * Maxiworx — nav.js
3	 * Einbinden auf JEDER Unterseite.
4	 * Enthält: Nav-Scroll-Effekt, Hero-Animation, Hamburger, Slideshow, Scroll-Reveal.
5	 */
6	(function () {
7	  'use strict';
8	
9	  /* ============================================================
10	     NAV SCROLL-EFFEKT & HERO-ANIMATION
11	  ============================================================ */
12	  const nav         = document.getElementById('site-nav');
13	  const heroTitle   = document.getElementById('hero-title');
14	  const heroTagline = document.getElementById('hero-tagline');
15	  const heroPre     = document.querySelector('.hero-pre');
16	  const navLogo     = document.querySelector('.nav-logo');
17	  const navSub      = document.querySelector('.nav-brand-sub');
18	  const navDivider  = document.querySelector('.nav-brand-divider');
19	
20	  /* Nav-Logo startet unsichtbar (nur auf Main-Page mit Hero) */
21	  const hasHero = !!heroTitle;
22	
23	  if (hasHero && navLogo) {
24	    navLogo.style.opacity   = '0';
25	    navLogo.style.transform = 'translateY(8px)';
26	    navLogo.style.transition = 'none';
27	    requestAnimationFrame(() => {
28	      navLogo.style.transition = 'opacity 350ms ease, transform 350ms ease';
29	    });
30	  }
31	
32	  /* CSS-Animation abwarten, dann JS übernehmen */
33	  let jsReady = !hasHero; /* Auf Unterseiten sofort ready */
34	  if (hasHero) {
35	    setTimeout(() => {
36	      jsReady = true;
37	      [heroTitle, heroTagline, heroPre].forEach(el => {
38	        if (!el) return;
39	        el.style.animation  = 'none';
40	        el.style.opacity    = '1';
41	        el.style.transform  = 'translateY(0)';
42	        el.style.willChange = 'transform, opacity';
43	      });
44	    }, 1650);
45	  }
46	
47	  const START = 40;
48	  const END   = 280;
49	
50	  function clamp(v)       { return Math.min(Math.max(v, 0), 1); }
51	  function lerp(a, b, t)  { return a + (b - a) * clamp(t); }
52	  function prog(y, s, e)  { return clamp((y - s) / (e - s)); }
53	
54	  function onScroll() {
55	    const y = window.scrollY;
56	    const t = prog(y, START, END);
57	
58	    /* Nav Glas */
59	    nav?.classList.toggle('nav--scrolled', y > START);
60	
61	    if (!jsReady || !hasHero) return;
62	
63	    /* Hero-Titel */
64	    if (heroTitle) {
65	      heroTitle.style.transform = `translateY(${lerp(0, -100, t)}px)`;
66	      heroTitle.style.opacity   = lerp(1, 0, t * 1.4).toFixed(3);
67	    }
68	    /* Tagline */
69	    if (heroTagline) {
70	      const tg = prog(y, START, END * 0.6);
71	      heroTagline.style.transform = `translateY(${lerp(0, -50, tg)}px)`;
72	      heroTagline.style.opacity   = lerp(1, 0, tg * 1.6).toFixed(3);
73	    }
74	    /* Pre-Text */
75	    if (heroPre) {
76	      const tp = prog(y, START, END * 0.4);
77	      heroPre.style.transform = `translateY(${lerp(0, -30, tp)}px)`;
78	      heroPre.style.opacity   = lerp(1, 0, tp * 2).toFixed(3);
79	    }
80	    /* Nav-Logo einblenden */
81	    if (navLogo) {
82	      const lt = prog(y, END * 0.35, END * 0.85);
83	      navLogo.style.opacity   = lt.toFixed(3);
84	      navLogo.style.transform = `translateY(${lerp(8, 0, lt)}px)`;
85	    }
86	    /* Nav-Sub */
87	    const st = prog(y, END * 0.80, END);
88	    if (navSub)     { navSub.style.maxWidth = st > 0 ? '260px' : '0'; navSub.style.opacity = st.toFixed(3); }
89	    if (navDivider) { navDivider.style.opacity = st.toFixed(3); }
90	  }
91	
92	  window.addEventListener('scroll', onScroll, { passive: true });
93	  onScroll();
94	
95	  /* ============================================================
96	     HAMBURGER MENÜ
97	  ============================================================ */
98	  const hamburger  = document.getElementById('hamburger');
99	  const mobileNav  = document.getElementById('mobile-nav');
100	  const body       = document.body;
101	
102	  function openMobileNav() {
103	    hamburger?.classList.add('is-open');
104	    mobileNav?.classList.add('is-open');
105	    hamburger?.setAttribute('aria-expanded', 'true');
106	    body.style.overflow = 'hidden'; /* Scrollen sperren */
107	  }
108	
109	  function closeMobileNav() {
110	    hamburger?.classList.remove('is-open');
111	    mobileNav?.classList.remove('is-open');
112	    hamburger?.setAttribute('aria-expanded', 'false');
