// ── Raw (unescaped) value — use only for trusted HTML content ─────────────────
function cRaw(array $content, string $key, ?string $lang = null): string
{
    $lang ??= cmsLang();
    $row = $content[$key] ?? null;
    if ($row === null) return '';
    $val = $row[$lang] ?? '';
    if ($val === '' && $lang !== 'de') {
        $val = $row['de'] ?? '';
    }
    return $val;
}

// ── Feature flag helper ───────────────────────────────────────────────────────
function cmsFlag(string $key): bool
{
    static $flags = null;
    if ($flags === null) {
        try {
            $db   = getDbConnection();
            $stmt = $db->query("SELECT setting_key, value FROM cms_settings WHERE type='bool'");
            $flags = [];
            foreach ($stmt->fetchAll(PDO::FETCH_ASSOC) as $row) {
                $flags[$row['setting_key']] = $row['value'] === '1';
            }
        } catch (\Throwable) {
            $flags = [];
        }
    }
    return $flags[$key] ?? false;
}

// ── Media slot helper ─────────────────────────────────────────────────────────
function cmsMedia(string $pageSlug, string $slotKey): string
{
    static $slots = [];
    $cacheKey = $pageSlug . ':' . $slotKey;
    if (isset($slots[$cacheKey])) return $slots[$cacheKey];
    try {
        $db   = getDbConnection();
        $stmt = $db->prepare(
            'SELECT m.storage_path FROM cms_media_slots s
             JOIN cms_media m ON m.id = s.media_id
             WHERE s.page_slug = ? AND s.slot_key = ? LIMIT 1'
        );
        $stmt->execute([$pageSlug, $slotKey]);
        $path = $stmt->fetchColumn();
        $slots[$cacheKey] = $path ? '/maxiworx/cms/uploads/' . $path : '';
    } catch (\Throwable) {
        $slots[$cacheKey] = '';
    }
    return $slots[$cacheKey];
}

// ── Price status helper ───────────────────────────────────────────────────────
/**
 * Renders price block or alternative based on price_status field.
 * @param array  $content   page content array
 * @param string $prefix    e.g. 'recording' → looks for recording.price, recording.unit etc.
 * @return string  HTML
 */
function cmsPriceBlock(array $content, string $prefix, string $lang = 'de'): string
{
    $row    = $content[$prefix . '.price_status'] ?? null;
    $status = $row[$lang] ?? $row['de'] ?? 'visible';

    if ($status === 'hidden') {
        return '';
    }
    if ($status === 'on_request') {
        return '<div class="price-on-request">Preis auf Anfrage</div>';
    }

    $price = htmlspecialchars(cRaw($content, $prefix . '.price', $lang));
    $unit  = htmlspecialchars(cRaw($content, $prefix . '.unit', $lang));
    $note  = htmlspecialchars(cRaw($content, $prefix . '.note', $lang));

    return '<div class="service-card__price">
        <div class="price-amount">' . $price . '</div>
        <div class="price-unit">' . $unit . '</div>
        ' . ($note ? '<div class="price-note">' . $note . '</div>' : '') . '
    </div>';
}

