require('dotenv').config();
const chokidar = require('chokidar');
const SftpClient = require('ssh2-sftp-client');
const path = require('path');

const {
  SFTP_HOST,
  SFTP_USER,
  SFTP_PASS,
  SFTP_PORT = '22',
  SFTP_REMOTE_PATH,
} = process.env;

if (!SFTP_HOST || !SFTP_USER || !SFTP_PASS || !SFTP_REMOTE_PATH) {
  console.error('Missing required SFTP_* variables in .env');
  process.exit(1);
}

const LOCAL_ROOT = __dirname;
const DELAY_MS   = 500;

const IGNORED = [
  /(^|[/\\])\../,
  /node_modules/,
  /watch\.js$/,
];

// --- persistent connection ---------------------------------------------------

const sftp = new SftpClient();
let connected = false;

async function ensureConnected() {
  if (connected) return;
  await sftp.connect({
    host:     SFTP_HOST,
    port:     parseInt(SFTP_PORT, 10),
    username: SFTP_USER,
    password: SFTP_PASS,
  });
  connected = true;
  console.log(`[sftp] connected to ${SFTP_HOST}`);
}

sftp.on('close', () => { connected = false; console.log('[sftp] connection closed — will reconnect on next upload'); });
sftp.on('error', (err) => { connected = false; console.error('[sftp] connection error:', err.message); });

// --- serial upload queue -----------------------------------------------------

const queue   = [];
let running   = false;

function enqueue(localPath) {
  if (!queue.includes(localPath)) {
    queue.push(localPath);
  }
  if (!running) processQueue();
}

async function processQueue() {
  if (queue.length === 0) { running = false; return; }
  running = true;

  const localPath  = queue.shift();
  const relative   = path.relative(LOCAL_ROOT, localPath).replace(/\\/g, '/');
  const remotePath = `${SFTP_REMOTE_PATH}/${relative}`;

  try {
    await ensureConnected();
    const remoteDir = remotePath.substring(0, remotePath.lastIndexOf('/'));
    await sftp.mkdir(remoteDir, true);
    await sftp.put(localPath, remotePath);
    console.log(`[upload] ${relative} -> ${remotePath}`);
  } catch (err) {
    console.error(`[error]  ${relative}: ${err.message}`);
    connected = false; // force reconnect on next item
  }

  // wait before processing the next file
  setTimeout(processQueue, DELAY_MS);
}

// --- watcher -----------------------------------------------------------------

const watcher = chokidar.watch(LOCAL_ROOT, {
  ignored:          IGNORED,
  persistent:       true,
  ignoreInitial:    true,
  awaitWriteFinish: { stabilityThreshold: 300, pollInterval: 100 },
});

watcher
  .on('add',    enqueue)
  .on('change', enqueue)
  .on('error',  (err) => console.error('[watcher error]', err));

console.log(`Watching ${LOCAL_ROOT} for changes...`);
console.log(`Uploading to ${SFTP_HOST}:${SFTP_REMOTE_PATH} (queue delay: ${DELAY_MS}ms)`);

