require('dotenv').config();
const chokidar   = require('chokidar');
const SftpClient = require('ssh2-sftp-client');
const path       = require('path');

// ---------------------------------------------------------------------------
// Config — all env vars coerced to plain strings
// ---------------------------------------------------------------------------
const SFTP_HOST        = String(process.env.SFTP_HOST        || '');
const SFTP_USER        = String(process.env.SFTP_USER        || '');
const SFTP_PASS        = String(process.env.SFTP_PASS        || '');
const SFTP_PORT        = String(process.env.SFTP_PORT        || '22');
// Remote base is always ./maxiworx regardless of what .env says
const SFTP_REMOTE_PATH = './maxiworx';

if (!SFTP_HOST || !SFTP_USER || !SFTP_PASS) {
  console.error('[config] Missing SFTP_HOST, SFTP_USER or SFTP_PASS in .env');
  process.exit(1);
}

const LOCAL_ROOT           = __dirname;
const QUEUE_DELAY_MS       = 500;   // pause between uploads
const CONNECT_DELAY_MS     = 1500;  // wait after startup before first connect
const HANDSHAKE_TIMEOUT_MS = 40000; // 40s — handles extreme mobile latency
const KEEPALIVE_MS         = 10000; // prevent idle-drop on hotspot
const MAX_RETRIES          = 3;     // reconnect attempts per file

const CONNECT_OPTIONS = {
  host:              SFTP_HOST,
  port:              parseInt(SFTP_PORT, 10),
  username:          SFTP_USER,
  password:          SFTP_PASS,
  readyTimeout:      HANDSHAKE_TIMEOUT_MS,
  keepaliveInterval: KEEPALIVE_MS,
  // password-only — skip publickey / keyboard-interactive round-trips
  authHandler:       ['password'],
  tryKeyboard:       false,
  agent:             false,
  privateKey:        undefined,
};

// ---------------------------------------------------------------------------
// Persistent SFTP connection with retry logic
// ---------------------------------------------------------------------------
const sftp = new SftpClient();
let connected = false;

sftp.on('close', () => {
  connected = false;
  console.log('[sftp] connection closed — will reconnect on next upload');
});
sftp.on('error', (err) => {
  connected = false;
  console.error('[sftp] connection error:', err.message);
});

async function ensureConnected(attempt = 1) {
  if (connected) return;

  try {
    console.log(`[sftp] connecting to ${SFTP_HOST}:${SFTP_PORT} (attempt ${attempt}/${MAX_RETRIES})…`);
    await sftp.connect(CONNECT_OPTIONS);
    connected = true;
    console.log(`[sftp] connected to ${SFTP_HOST} → remote base: ${SFTP_REMOTE_PATH}`);
  } catch (err) {
    connected = false;
    console.error(`[sftp] connect failed (attempt ${attempt}): ${err.message}`);

    if (attempt < MAX_RETRIES) {
      const backoff = attempt * 3000; // 3s, 6s between retries
      console.log(`[sftp] retrying in ${backoff / 1000}s…`);
      await new Promise(r => setTimeout(r, backoff));
      return ensureConnected(attempt + 1);
    }

    throw new Error(`Could not connect after ${MAX_RETRIES} attempts: ${err.message}`);
  }
}

// ---------------------------------------------------------------------------
// Serial upload queue
// ---------------------------------------------------------------------------
const queue  = [];
let running  = false;

function enqueue(localPath) {
  if (!queue.includes(localPath)) {
    queue.push(localPath);
    console.log(`[queue]  +${path.relative(LOCAL_ROOT, localPath).replace(/\\/g, '/')} (${queue.length} pending)`);
  }
  if (!running) processQueue();
}

async function processQueue() {
  if (queue.length === 0) { running = false; return; }
  running = true;

  const localPath  = queue.shift();
  const relative   = path.relative(LOCAL_ROOT, localPath).replace(/\\/g, '/');
  const remotePath = `${SFTP_REMOTE_PATH}/${relative}`;
  const remoteDir  = remotePath.substring(0, remotePath.lastIndexOf('/'));

  try {
    await ensureConnected();          // reconnects + retries if needed
    await sftp.mkdir(remoteDir, true);
    await sftp.put(localPath, remotePath);
    console.log(`[upload] ${relative} → ${remotePath}`);
  } catch (err) {
    console.error(`[error]  ${relative}: ${err.message}`);
    connected = false;                // force fresh connect for next file
  }

  setTimeout(processQueue, QUEUE_DELAY_MS);
}

// ---------------------------------------------------------------------------
// Chokidar watcher — armed after CONNECT_DELAY_MS
// ---------------------------------------------------------------------------
const IGNORED = [
  /(^|[/\\])\../,   // dot-files / dot-folders
  /node_modules/,
  /watch\.js$/,
];

const watcher = chokidar.watch(LOCAL_ROOT, {
  ignored:          IGNORED,
  persistent:       true,
  ignoreInitial:    true,
  awaitWriteFinish: { stabilityThreshold: 300, pollInterval: 100 },
});

setTimeout(() => {
  watcher
    .on('add',    enqueue)
    .on('change', enqueue)
    .on('error',  (err) => console.error('[watcher error]', err));

  console.log('');
  console.log(`[watch]  ${LOCAL_ROOT}`);
  console.log(`[target] ${SFTP_HOST}:${SFTP_PORT} → ${SFTP_REMOTE_PATH}`);
  console.log(`[config] handshake: ${HANDSHAKE_TIMEOUT_MS / 1000}s  keepalive: ${KEEPALIVE_MS / 1000}s  retries: ${MAX_RETRIES}  queue-delay: ${QUEUE_DELAY_MS}ms`);
  console.log('');
}, CONNECT_DELAY_MS);

