140	  console.log('');
141	  console.log(`[watch]  ${LOCAL_ROOT}`);
142	  console.log(`[target] ${SFTP_HOST}:${SFTP_PORT} → ${SFTP_REMOTE_PATH}`);
143	  console.log(`[config] handshake: ${HANDSHAKE_TIMEOUT_MS / 1000}s  keepalive: ${KEEPALIVE_MS / 1000}s  retries: ${MAX_RETRIES}  queue-delay: ${QUEUE_DELAY_MS}ms`);
144	  console.log('');
145	}, CONNECT_DELAY_MS);

