1	/* ============================================================
2	   MAXIWORX 2026 — Design System
3	   "Where Nature Distills High-End Tech"
4	   
5	   Autor:    Lead Developer
6	   Stack:    Vanilla CSS, XAMPP/Apache, PHP 8.5+
7	   Version:  1.0.0
8	   ============================================================ */
9	
10	/* ------------------------------------------------------------
11	   1. GOOGLE FONTS IMPORT
12	   ------------------------------------------------------------ */
13	@import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;0,600;1,300;1,400;1,500&family=Inter:wght@300;400;500;600&family=Cormorant:ital,wght@0,300;1,300&display=swap');
14	
15	
16	/* ------------------------------------------------------------
17	   2. CSS CUSTOM PROPERTIES (Design Tokens)
18	   ------------------------------------------------------------ */
19	:root {
20	
21	  /* --- Farben: Basis --- */
22	  --color-bg-base:        #080808;   /* Tiefstes Schwarz — Haupt-Hintergrund */
23	  --color-bg-deep:        #0D0D0D;   /* Hintergrund fixiert (parallax layer) */
24	  --color-bg-card:        #141414;   /* Cards, Sektionen */
25	  --color-bg-card-hover:  #1C1C1C;   /* Card hover state */
26	  --color-bg-surface:     #1A1A1A;   /* Surfaces, modals */
27	  --color-bg-input:       #111111;   /* Formularfelder */
28	  --color-bg-overlay:     rgba(8, 8, 8, 0.75); /* Overlay über Hintergrundbild */
29	
30	  /* --- Farben: Text --- */
31	  --color-text-primary:   #F0EDE8;   /* Headlines — warmes Weiß */
32	  --color-text-secondary: #A8A49E;   /* Subheadlines, Labels */
33	  --color-text-muted:     #5C5955;   /* Muted text, Metadaten */
34	  --color-text-inverse:   #0A0A0A;   /* Text auf hellen Flächen */
35	
36	  /* --- Farben: Akzent Gold (Kern-Identität) --- */
37	  --color-gold:           #C8922A;   /* Primärer Gold-Akzent */
38	  --color-gold-light:     #D4A843;   /* Hover, highlights */
39	  --color-gold-dim:       #8A6420;   /* Subtle gold (borders, dividers) */
40	  --color-gold-glow:      rgba(200, 146, 42, 0.15); /* Gold glow effect */
41	  --color-gold-glow-strong: rgba(200, 146, 42, 0.30);
42	
43	  /* --- Farben: Blau (Tech-Akzent, nur CTA) --- */
44	  --color-blue:           #3A7BD5;   /* CTA Button */
45	  --color-blue-hover:     #4A8BE5;
46	  --color-blue-glow:      rgba(58, 123, 213, 0.20);
47	
48	  /* --- Farben: Borders --- */
49	  --color-border:         rgba(255, 255, 255, 0.06);
50	  --color-border-hover:   rgba(255, 255, 255, 0.12);
51	  --color-border-gold:    rgba(200, 146, 42, 0.25);
52	  --color-border-gold-strong: rgba(200, 146, 42, 0.50);
53	
54	  /* --- Glassmorphism --- */
55	  --glass-bg:             rgba(20, 20, 20, 0.60);
56	  --glass-bg-light:       rgba(30, 30, 30, 0.40);
57	  --glass-blur:           blur(20px);
58	  --glass-blur-heavy:     blur(40px);
59	  --glass-border:         1px solid rgba(255, 255, 255, 0.08);
60	  --glass-border-gold:    1px solid rgba(200, 146, 42, 0.20);
61	
62	  /* --- Typografie: Familien --- */
63	  --font-display:   'Cormorant Garamond', 'Georgia', serif;   /* Headlines, Logo */
64	  --font-body:      'Inter', 'Helvetica Neue', sans-serif;    /* UI, Body-Text */
65	  --font-caption:   'Cormorant', 'Georgia', serif;            /* Kursiv-Captions */
66	
67	  /* --- Typografie: Größen (fluid clamp-basiert) --- */
68	  --text-xs:        0.688rem;   /* 11px */
69	  --text-sm:        0.813rem;   /* 13px */
70	  --text-base:      0.938rem;   /* 15px */
71	  --text-md:        1.063rem;   /* 17px */
72	  --text-lg:        1.25rem;    /* 20px */
73	  --text-xl:        1.5rem;     /* 24px */
74	  --text-2xl:       2rem;       /* 32px */
75	  --text-3xl:       clamp(2.5rem, 5vw, 4rem);      /* ~40-64px */
76	  --text-4xl:       clamp(3.5rem, 7vw, 6rem);      /* ~56-96px */
77	  --text-hero:      clamp(4rem,  10vw, 8.5rem);    /* Hero-Titel */
78	
79	  /* --- Typografie: Gewichte --- */
80	  --weight-light:   300;
81	  --weight-regular: 400;
82	  --weight-medium:  500;
83	  --weight-semibold:600;
84	
85	  /* --- Spacing --- */
86	  --space-1:  0.25rem;   /*  4px */
87	  --space-2:  0.5rem;    /*  8px */
88	  --space-3:  0.75rem;   /* 12px */
89	  --space-4:  1rem;      /* 16px */
90	  --space-5:  1.25rem;   /* 20px */
91	  --space-6:  1.5rem;    /* 24px */
92	  --space-8:  2rem;      /* 32px */
93	  --space-10: 2.5rem;    /* 40px */
94	  --space-12: 3rem;      /* 48px */
95	  --space-16: 4rem;      /* 64px */
96	  --space-20: 5rem;      /* 80px */
97	  --space-24: 6rem;      /* 96px */
98	  --space-32: 8rem;      /* 128px */
99	
100	  /* --- Border Radius --- */
101	  --radius-sm:   4px;
102	  --radius-md:   8px;
103	  --radius-lg:   12px;
104	  --radius-xl:   20px;
105	  --radius-full: 9999px;
106	
107	  /* --- Shadows --- */
108	  --shadow-sm:    0 1px 3px rgba(0,0,0,0.40);
109	  --shadow-md:    0 4px 16px rgba(0,0,0,0.50);
110	  --shadow-lg:    0 8px 32px rgba(0,0,0,0.60);
111	  --shadow-xl:    0 16px 64px rgba(0,0,0,0.70);
112	  --shadow-gold:  0 4px 24px rgba(200, 146, 42, 0.20);
113	  --shadow-gold-strong: 0 8px 40px rgba(200, 146, 42, 0.35);
114	
115	  /* --- Transitions --- */
116	  --transition-fast:   150ms cubic-bezier(0.4, 0, 0.2, 1);
117	  --transition-base:   250ms cubic-bezier(0.4, 0, 0.2, 1);
118	  --transition-slow:   400ms cubic-bezier(0.4, 0, 0.2, 1);
119	  --transition-spring: 500ms cubic-bezier(0.34, 1.56, 0.64, 1);
120	
121	  /* --- Layout --- */
122	  --container-max:   1280px;
123	  --container-wide:  1440px;
124	  --nav-height:      64px;
125	  --nav-height-scrolled: 52px;
126	
127	  /* --- Z-Index Skala --- */
128	  --z-base:     0;
129	  --z-above:    10;
130	  --z-overlay:  20;
131	  --z-modal:    30;
132	  --z-nav:      40;
133	  --z-toast:    50;
134	
135	  /* --- Bento Grid --- */
136	  --bento-gap:  16px;
137	  --bento-gap-sm: 10px;
138	}
139	
140	
141	/* ------------------------------------------------------------
142	   3. CSS RESET & BASE
143	   ------------------------------------------------------------ */
144	*, *::before, *::after {
145	  box-sizing: border-box;
146	  margin: 0;
147	  padding: 0;
148	}
149	
150	html {
151	  scroll-behavior: smooth;
152	  font-size: 16px;
153	  -webkit-text-size-adjust: 100%;
154	  text-size-adjust: 100%;
155	}
156	
157	body {
158	  background-color: var(--color-bg-base);
159	  color: var(--color-text-primary);
160	  font-family: var(--font-body);
161	  font-size: var(--text-base);
162	  font-weight: var(--weight-regular);
163	  line-height: 1.6;
164	  -webkit-font-smoothing: antialiased;
165	  -moz-osx-font-smoothing: grayscale;
166	  overflow-x: hidden;
167	}
168	
169	img, video {
170	  display: block;
171	  max-width: 100%;
172	  height: auto;
173	}
174	
175	a {
176	  color: inherit;
177	  text-decoration: none;
178	}
179	
180	button {
181	  cursor: pointer;
182	  border: none;
183	  background: none;
184	  font-family: inherit;
185	}
186	
187	input, textarea, select {
188	  font-family: inherit;
189	  font-size: inherit;
190	  color: inherit;
191	}
192	
193	ul, ol {
194	  list-style: none;
195	}
196	
197	::selection {
198	  background: var(--color-gold-glow-strong);
199	  color: var(--color-gold-light);
200	}
201	
202	/* Scrollbar Styling */
203	::-webkit-scrollbar {
204	  width: 6px;
205	  height: 6px;
206	}
207	::-webkit-scrollbar-track {
208	  background: var(--color-bg-base);
209	}
210	::-webkit-scrollbar-thumb {
211	  background: var(--color-gold-dim);
212	  border-radius: var(--radius-full);
213	}
214	::-webkit-scrollbar-thumb:hover {
215	  background: var(--color-gold);
216	}
217	
218	
219	/* ------------------------------------------------------------
220	   4. TYPOGRAFIE-SYSTEM
221	   ------------------------------------------------------------ */
222	
223	/* Display / Hero */
224	.t-hero {
225	  font-family: var(--font-display);
226	  font-size: var(--text-hero);
227	  font-weight: var(--weight-light);
228	  letter-spacing: 0.15em;
229	  text-transform: uppercase;
230	  line-height: 1.0;
231	  color: var(--color-text-primary);
232	}
233	
234	.t-display {
235	  font-family: var(--font-display);
236	  font-size: var(--text-4xl);
237	  font-weight: var(--weight-light);
238	  letter-spacing: 0.04em;
239	  line-height: 1.1;
240	  color: var(--color-text-primary);
241	}
242	
243	.t-heading {
244	  font-family: var(--font-display);
245	  font-size: var(--text-3xl);
246	  font-weight: var(--weight-light);
247	  letter-spacing: 0.02em;
248	  line-height: 1.15;
249	  color: var(--color-text-primary);
250	}
251	
252	.t-subheading {
253	  font-family: var(--font-display);
254	  font-size: var(--text-xl);
255	  font-weight: var(--weight-regular);
256	  letter-spacing: 0.01em;
257	  line-height: 1.3;
258	  color: var(--color-text-primary);
259	}
260	
261	/* Tagline (kursiv, gold) */
262	.t-tagline {
263	  font-family: var(--font-display);
264	  font-style: italic;
265	  font-size: clamp(0.875rem, 2vw, 1.125rem);
266	  font-weight: var(--weight-light);
267	  letter-spacing: 0.25em;
268	  text-transform: uppercase;
269	  color: var(--color-gold);
270	  line-height: 1.4;
271	}
272	
273	/* Label / Overline (Kategorie-Labels, z.B. "PORTFOLIO") */
274	.t-label {
275	  font-family: var(--font-body);
276	  font-size: var(--text-xs);
277	  font-weight: var(--weight-medium);
278	  letter-spacing: 0.20em;
279	  text-transform: uppercase;
280	  color: var(--color-gold);
281	  line-height: 1.4;
282	}
283	
284	/* Body Text */
285	.t-body {
286	  font-family: var(--font-body);
287	  font-size: var(--text-base);
288	  font-weight: var(--weight-light);
289	  line-height: 1.75;
290	  color: var(--color-text-secondary);
291	}
292	
293	.t-body-sm {
294	  font-family: var(--font-body);
295	  font-size: var(--text-sm);
296	  font-weight: var(--weight-light);
297	  line-height: 1.65;
298	  color: var(--color-text-secondary);
299	}
300	
301	/* Nav Text */
302	.t-nav {
303	  font-family: var(--font-body);
304	  font-size: var(--text-sm);
305	  font-weight: var(--weight-medium);
306	  letter-spacing: 0.06em;
307	  text-transform: uppercase;
308	  color: var(--color-text-secondary);
309	}
310	
311	/* Caption (kursiv serif) */
312	.t-caption {
313	  font-family: var(--font-caption);
314	  font-style: italic;
315	  font-size: var(--text-sm);
316	  font-weight: var(--weight-light);
317	  color: var(--color-text-muted);
318	  letter-spacing: 0.02em;
319	}
320	
321	/* Muted */
322	.t-muted {
323	  color: var(--color-text-muted);
324	}
325	
326	/* Gold highlight */
327	.t-gold {
328	  color: var(--color-gold);
329	}
330	
331	
332	/* ------------------------------------------------------------
333	   5. LAYOUT UTILITIES
334	   ------------------------------------------------------------ */
335	.container {
336	  width: 100%;
337	  max-width: var(--container-max);
338	  margin-inline: auto;
339	  padding-inline: var(--space-6);
340	}
341	
342	.container--wide {
343	  max-width: var(--container-wide);
344	  padding-inline: var(--space-8);
345	}
346	
347	.container--narrow {
348	  max-width: 860px;
349	}
350	
351	/* Section Padding */
352	.section {
353	  padding-block: var(--space-24);
354	  position: relative;
355	}
356	
357	.section--lg {
358	  padding-block: var(--space-32);
359	}
360	
361	.section--sm {
362	  padding-block: var(--space-16);
363	}
364	
365	/* Flex helpers */
366	.flex       { display: flex; }
367	.flex-col   { flex-direction: column; }
368	.items-center { align-items: center; }
369	.justify-between { justify-content: space-between; }
370	.gap-4      { gap: var(--space-4); }
371	.gap-6      { gap: var(--space-6); }
372	.gap-8      { gap: var(--space-8); }
373	
374	
375	/* ------------------------------------------------------------
376	   6. PARALLAX / FIXED BACKGROUND SYSTEM
377	   ------------------------------------------------------------ */
378	
379	/* Der fixierte Hintergrund bleibt an Ort und Stelle.
380	   Inhalts-Sektionen "floaten" darüber beim Scrollen. */
381	.bg-fixed-layer,
382	.bg-fixed {
383	  position: fixed;
384	  inset: 0;
385	  z-index: var(--z-base);
386	  background-color: var(--color-bg-deep);
387	  /* Echtes Foto: background-image: url('../images/studio-bg.jpg'); */
388	  background-image:
389	    radial-gradient(ellipse 80% 60% at 50% 30%,
390	      rgba(200, 146, 42, 0.04) 0%,
391	      transparent 60%),
392	    radial-gradient(ellipse 60% 80% at 20% 80%,
393	      rgba(58, 123, 213, 0.03) 0%,
394	      transparent 50%),
395	    linear-gradient(
396	      160deg,
397	      #0A0A08 0%,
398	      #0E0E0C 25%,
399	      #101010 50%,
400	      #0C0C0A 75%,
401	      #080808 100%
402	    );
403	  background-size: cover;
404	  background-position: center top;
405	  background-attachment: fixed;
406	}
407	
408	/* Overlay für Lesbarkeit über dem Hintergrundfoto */
409	.bg-fixed-layer::after,
410	.bg-fixed::after {
411	  content: '';
412	  position: absolute;
413	  inset: 0;
414	  background: var(--color-bg-overlay);
415	}
416	
417	/* Alle Sektions-Inhalte liegen über dem fixierten BG */
418	.site-content {
419	  position: relative;
420	  z-index: var(--z-above);
421	}
422	
423	/* Sektionen mit eigenem Hintergrund (Cards-Bereiche) */
424	.section--opaque {
425	  background: var(--color-bg-card);
426	}
427	
428	.section--glass {
429	  background: var(--glass-bg);
430	  backdrop-filter: var(--glass-blur);
431	  -webkit-backdrop-filter: var(--glass-blur);
432	  border-top: var(--glass-border);
433	  border-bottom: var(--glass-border);
434	}
435	
436	
437	/* ------------------------------------------------------------
438	   7. NAVIGATION
439	   ------------------------------------------------------------ */
440	.site-nav {
441	  position: fixed;
442	  top: 0;
443	  left: 0;
444	  right: 0;
445	  z-index: var(--z-nav);
446	  height: var(--nav-height);
447	  display: flex;
448	  align-items: center;
449	  transition: height var(--transition-slow),
450	              background var(--transition-slow),
451	              backdrop-filter var(--transition-slow);
452	}
453	
454	/* Transparente Nav im Hero-Bereich */
455	.site-nav--transparent {
456	  background: transparent;
457	}
458	
459	/* Verglaste Nav beim Scrollen — nav.js adds .nav--scrolled */
460	.site-nav--scrolled,
461	.site-nav.nav--scrolled {
462	  height: var(--nav-height-scrolled);
463	  background: rgba(12, 12, 10, 0.72);
464	  backdrop-filter: blur(28px) saturate(1.4);
465	  -webkit-backdrop-filter: blur(28px) saturate(1.4);
466	  border-color: rgba(255, 255, 255, 0.08);
467	  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.4), inset 0 1px 0 rgba(255, 255, 255, 0.05);
468	}
469	
470	.nav-inner {
471	  width: 100%;
472	  max-width: var(--container-max);
473	  margin-inline: auto;
474	  padding-inline: var(--space-6);
475	  display: flex;
476	  align-items: center;
477	  justify-content: space-between;
478	  gap: var(--space-8);
479	}
480	
481	/* Logo */
482	.nav-logo {
483	  font-family: var(--font-display);
484	  font-size: 1.25rem;
485	  font-weight: var(--weight-medium);
486	  letter-spacing: 0.12em;
487	  text-transform: uppercase;
488	  color: var(--color-text-primary);
489	  white-space: nowrap;
490	  transition: opacity var(--transition-base);
491	}
492	
493	/* Nav-Titel-Integration (erscheint beim Scrollen) */
494	.nav-hero-title {
495	  display: flex;
496	  flex-direction: column;
497	  align-items: flex-start;
498	  overflow: hidden;
499	  max-height: 0;
500	  opacity: 0;
501	  transition:
502	    max-height var(--transition-slow),
503	    opacity var(--transition-slow);
504	}
505	
506	.site-nav--scrolled .nav-hero-title {
507	  max-height: 40px;
508	  opacity: 1;
509	}
510	
511	.nav-hero-title .title {
512	  font-family: var(--font-display);
513	  font-size: var(--text-xs);
514	  font-weight: var(--weight-medium);
515	  letter-spacing: 0.18em;
516	  text-transform: uppercase;
517	  color: var(--color-text-primary);
518	  line-height: 1.2;
519	}
520	
521	.nav-hero-title .tagline {
522	  font-family: var(--font-display);
523	  font-style: italic;
524	  font-size: 0.625rem;
525	  letter-spacing: 0.14em;
526	  text-transform: uppercase;
527	  color: var(--color-gold);
528	  line-height: 1.2;
529	}
530	
531	/* Nav Links */
532	.nav-links {
533	  display: flex;
534	  align-items: center;
535	  gap: var(--space-6);
536	}
537	
538	.nav-link {
539	  font-family: var(--font-body);
540	  font-size: var(--text-xs);
541	  font-weight: var(--weight-medium);
542	  letter-spacing: 0.10em;
543	  text-transform: uppercase;
544	  color: var(--color-text-secondary);
545	  transition: color var(--transition-fast);
546	  position: relative;
547	  padding-block: var(--space-1);
548	}
549	
550	.nav-link::after {
551	  content: '';
552	  position: absolute;
553	  bottom: -2px;
554	  left: 0;
555	  width: 0;
556	  height: 1px;
557	  background: var(--color-gold);
558	  transition: width var(--transition-base);
559	}
560	
561	.nav-link:hover {
562	  color: var(--color-text-primary);
563	}
564	
565	.nav-link:hover::after,
566	.nav-link.active::after {
567	  width: 100%;
568	}
569	
570	.nav-link.active {
571	  color: var(--color-text-primary);
572	}
573	
574	/* CTA Button */
575	.btn-nav-cta {
576	  font-family: var(--font-body);
577	  font-size: var(--text-xs);
578	  font-weight: var(--weight-medium);
579	  letter-spacing: 0.10em;
580	  text-transform: uppercase;
581	  color: #ffffff;
582	  background: var(--color-blue);
583	  border: 1px solid var(--color-blue);
584	  border-radius: var(--radius-full);
585	  padding: var(--space-2) var(--space-5);
586	  transition:
587	    background var(--transition-fast),
588	    box-shadow var(--transition-fast),
589	    transform var(--transition-fast);
590	  white-space: nowrap;
591	}
592	
593	.btn-nav-cta:hover {
594	  background: var(--color-blue-hover);
595	  box-shadow: var(--color-blue-glow) 0 4px 20px;
596	  transform: translateY(-1px);
597	}
598	
599	.btn-nav-cta:active {
600	  transform: translateY(0);
601	}
602	
603	
604	/* ------------------------------------------------------------
605	   8. HERO SECTION
606	   ------------------------------------------------------------ */
607	.hero {
608	  position: relative;
609	  min-height: 100svh;
610	  display: flex;
611	  flex-direction: column;
612	  align-items: center;
613	  justify-content: center;
614	  text-align: center;
615	  padding-top: var(--nav-height);
616	  overflow: hidden;
617	}
618	
619	.hero-content {
620	  position: relative;
621	  z-index: 2;
622	  display: flex;
623	  flex-direction: column;
624	  align-items: center;
625	  gap: var(--space-5);
626	}
627	
628	/* Der Haupt-Titel — transformiert sich beim Scrollen */
629	.hero-title-wrap {
630	  display: flex;
631	  flex-direction: column;
632	  align-items: center;
633	  gap: var(--space-4);
634	  will-change: transform, opacity;
635	}
636	
637	.hero-title {
638	  font-family: var(--font-display);
639	  font-size: var(--text-hero);
640	  font-weight: var(--weight-light);
641	  letter-spacing: 0.18em;
642	  text-transform: uppercase;
643	  color: var(--color-text-primary);
644	  line-height: 0.95;
645	  text-shadow: 0 2px 40px rgba(0,0,0,0.8);
646	}
647	
648	.hero-tagline {
649	  font-family: var(--font-display);
650	  font-style: italic;
651	  font-size: clamp(0.75rem, 1.5vw, 1rem);
652	  font-weight: var(--weight-light);
653	  letter-spacing: 0.30em;
654	  text-transform: uppercase;
655	  color: var(--color-gold);
656	  text-shadow: 0 0 30px var(--color-gold-glow);
657	}
658	
659	/* Scroll-Indikator */
660	.hero-scroll-hint {
661	  position: absolute;
662	  bottom: var(--space-8);
663	  left: 50%;
664	  transform: translateX(-50%);
665	  display: flex;
666	  flex-direction: column;
667	  align-items: center;
668	  gap: var(--space-2);
669	  opacity: 0.5;
670	  animation: scrollBounce 2s ease-in-out infinite;
671	}
672	
673	.hero-scroll-hint span {
674	  font-size: var(--text-xs);
675	  letter-spacing: 0.15em;
676	  text-transform: uppercase;
677	  color: var(--color-text-muted);
678	}
679	
680	.scroll-line {
681	  width: 1px;
682	  height: 40px;
683	  background: linear-gradient(to bottom, var(--color-gold-dim), transparent);
684	}
685	
686	@keyframes scrollBounce {
687	  0%, 100% { transform: translateX(-50%) translateY(0); }
688	  50%       { transform: translateX(-50%) translateY(8px); }
689	}
690	
691	
692	/* ------------------------------------------------------------
693	   9. BENTO GRID SYSTEM
694	   ------------------------------------------------------------ */
695	.bento-grid {
696	  display: grid;
697	  gap: var(--bento-gap);
698	}
699	
700	/* Referenzen Grid (1 groß links, 2×2 rechts) */
701	.bento-grid--references {
702	  grid-template-columns: 1fr 1fr;
703	  grid-template-rows: auto;
704	}
705	
706	.bento-grid--references .bento-item:first-child {
707	  grid-row: span 2;
708	}
709	
710	/* 3-Spalten gleichmäßig */
711	.bento-grid--thirds {
712	  grid-template-columns: repeat(3, 1fr);
713	}
714	
715	/* 2 Spalten */
716	.bento-grid--halves {
717	  grid-template-columns: 1fr 1fr;
718	}
719	
720	/* Bento Item Basis */
721	.bento-item {
722	  position: relative;
723	  border-radius: var(--radius-lg);
724	  overflow: hidden;
725	  background: var(--color-bg-card);
726	  border: 1px solid var(--color-border);
727	  transition:
728	    border-color var(--transition-base),
729	    transform var(--transition-slow),
730	    box-shadow var(--transition-slow);
731	}
732	
733	.bento-item:hover {
734	  border-color: var(--color-border-gold);
735	  box-shadow: var(--shadow-gold);
736	}
737	
738	/* Bento mit Bild-Hintergrund */
739	.bento-item--image {
740	  aspect-ratio: 1 / 1;
741	  cursor: pointer;
742	}
743	
744	.bento-item--image .bento-image {
745	  position: absolute;
746	  inset: 0;
747	  width: 100%;
748	  height: 100%;
749	  object-fit: cover;
750	  transition: transform var(--transition-slow);
751	  filter: brightness(0.6) saturate(0.7);
752	}
753	
754	.bento-item--image:hover .bento-image {
755	  transform: scale(1.04);
756	  filter: brightness(0.75) saturate(0.85);
757	}
758	
759	.bento-item__label {
760	  position: absolute;
761	  bottom: var(--space-5);
762	  left: var(--space-5);
763	  right: var(--space-5);
764	}
765	
766	/* Bento Text-Card */
767	.bento-item--text {
768	  padding: var(--space-8);
769	  display: flex;
770	  flex-direction: column;
771	  gap: var(--space-4);
772	}
773	
774	
775	/* ------------------------------------------------------------
776	   10. CARDS & SURFACES
777	   ------------------------------------------------------------ */
778	
779	/* Standard Card */
780	.card {
781	  background: var(--color-bg-card);
782	  border: 1px solid var(--color-border);
783	  border-radius: var(--radius-lg);
784	  padding: var(--space-8);
785	  transition:
786	    border-color var(--transition-base),
787	    background var(--transition-base),
788	    box-shadow var(--transition-base);
789	}
790	
791	.card:hover {
792	  border-color: var(--color-border-hover);
793	  background: var(--color-bg-card-hover);
794	}
795	
796	/* Glas-Card */
797	.card--glass {
798	  background: var(--glass-bg);
799	  backdrop-filter: var(--glass-blur);
800	  -webkit-backdrop-filter: var(--glass-blur);
801	  border: var(--glass-border);
802	}
803	
804	.card--glass:hover {
805	  background: var(--glass-bg-light);
806	  border: var(--glass-border-gold);
807	  box-shadow: var(--shadow-gold);
808	}
809	
810	/* Gold-Akzent Card */
811	.card--gold {
812	  border-color: var(--color-border-gold);
813	}
814	
815	.card--gold:hover {
816	  border-color: var(--color-border-gold-strong);
817	  box-shadow: var(--shadow-gold-strong);
818	}
819	
820	/* Feature Card (Beyond the Booth) */
821	.feature-card {
822	  background: var(--color-bg-card);
823	  border: 1px solid var(--color-border);
824	  border-radius: var(--radius-lg);
825	  padding: var(--space-8) var(--space-6);
826	  display: flex;
827	  flex-direction: column;
828	  gap: var(--space-5);
829	  transition:
830	    border-color var(--transition-base),
831	    box-shadow var(--transition-base);
832	}
833	
834	.feature-card:hover {
835	  border-color: var(--color-border-gold);
836	  box-shadow: var(--shadow-gold);
837	}
838	
839	.feature-card__icon {
840	  width: 40px;
841	  height: 40px;
842	  color: var(--color-gold);
843	  opacity: 0.85;
844	}
845	
846	.feature-card__divider {
847	  width: 40px;
848	  height: 1px;
849	  background: var(--color-gold-dim);
850	  transition: width var(--transition-slow);
851	}
852	
853	.feature-card:hover .feature-card__divider {
854	  width: 80px;
855	}
856	
857	
858	/* ------------------------------------------------------------
859	   11. BUTTONS
860	   ------------------------------------------------------------ */
861	
862	/* Primär (blau, CTA) */
863	.btn {
864	  display: inline-flex;
865	  align-items: center;
866	  justify-content: center;
867	  gap: var(--space-2);
868	  font-family: var(--font-body);
869	  font-size: var(--text-sm);
870	  font-weight: var(--weight-medium);
871	  letter-spacing: 0.08em;
872	  text-transform: uppercase;
873	  border-radius: var(--radius-full);
874	  padding: var(--space-3) var(--space-8);
875	  transition:
876	    background var(--transition-fast),
877	    transform var(--transition-fast),
878	    box-shadow var(--transition-fast);
879	  white-space: nowrap;
880	  cursor: pointer;
881	}
882	
883	.btn--primary {
884	  background: var(--color-blue);
885	  color: #ffffff;
886	  border: 1px solid var(--color-blue);
887	}
888	
889	.btn--primary:hover {
890	  background: var(--color-blue-hover);
891	  box-shadow: 0 8px 30px var(--color-blue-glow);
892	  transform: translateY(-2px);
893	}
894	
895	/* Ghost (transparenter Rand) */
896	.btn--ghost {
897	  background: transparent;
898	  color: var(--color-text-secondary);
899	  border: 1px solid var(--color-border-hover);
900	}
901	
902	.btn--ghost:hover {
903	  color: var(--color-text-primary);
904	  border-color: var(--color-border-gold);
905	  box-shadow: var(--shadow-gold);
906	}
907	
908	/* Gold-Outline */
909	.btn--gold {
910	  background: transparent;
911	  color: var(--color-gold);
912	  border: 1px solid var(--color-border-gold-strong);
913	}
914	
915	.btn--gold:hover {
916	  background: var(--color-gold-glow);
917	  box-shadow: var(--shadow-gold);
918	  transform: translateY(-2px);
919	}
920	
921	/* Text-Link mit Pfeil */
922	.btn--link {
923	  background: transparent;
924	  border: none;
925	  color: var(--color-text-secondary);
926	  padding: 0;
927	  font-size: var(--text-sm);
928	  letter-spacing: 0.06em;
929	  text-transform: uppercase;
930	  display: inline-flex;
931	  align-items: center;
932	  gap: var(--space-2);
933	  transition: color var(--transition-fast), gap var(--transition-fast);
934	}
935	
936	.btn--link:hover {
937	  color: var(--color-text-primary);
938	  gap: var(--space-4);
939	}
940	
941	.btn--link .arrow {
942	  transition: transform var(--transition-fast);
943	}
944	
945	.btn--link:hover .arrow {
946	  transform: translateX(4px);
947	}
948	
949	
950	/* ------------------------------------------------------------
951	   12. FORMULAR-ELEMENTE
952	   ------------------------------------------------------------ */
953	.form-group {
954	  display: flex;
955	  flex-direction: column;
956	  gap: var(--space-2);
957	}
958	
959	.form-label {
960	  font-size: var(--text-xs);
961	  font-weight: var(--weight-medium);
962	  letter-spacing: 0.12em;
963	  text-transform: uppercase;
964	  color: var(--color-text-muted);
965	}
966	
967	.form-input {
968	  background: var(--color-bg-input);
969	  border: 1px solid var(--color-border);
970	  border-radius: var(--radius-md);
971	  padding: var(--space-3) var(--space-4);
972	  font-size: var(--text-sm);
973	  color: var(--color-text-primary);
974	  transition:
975	    border-color var(--transition-fast),
976	    box-shadow var(--transition-fast);
977	  outline: none;
978	  width: 100%;
979	}
980	
981	.form-input::placeholder {
982	  color: var(--color-text-muted);
983	}
984	
985	.form-input:focus {
986	  border-color: var(--color-border-gold);
987	  box-shadow: 0 0 0 3px var(--color-gold-glow);
988	}
989	
990	.form-input:hover:not(:focus) {
991	  border-color: var(--color-border-hover);
992	}
993	
994	
995	/* ------------------------------------------------------------
996	   13. DIVIDER & DEKORATION
997	   ------------------------------------------------------------ */
998	
999	/* Gold-Divider */
1000	.divider-gold {
1001	  width: 60px;
1002	  height: 1px;
1003	  background: linear-gradient(to right, var(--color-gold), transparent);
1004	}
1005	
1006	.divider-gold--center {
1007	  margin-inline: auto;
1008	  background: linear-gradient(to right, transparent, var(--color-gold), transparent);
1009	  width: 120px;
1010	}
1011	
1012	/* Section Eyebrow (Label + Line) */
1013	.section-eyebrow {
1014	  display: flex;
1015	  align-items: center;
1016	  gap: var(--space-4);
1017	  margin-bottom: var(--space-4);
1018	}
1019	
1020	.section-eyebrow::before {
1021	  content: '';
1022	  width: 24px;
1023	  height: 1px;
1024	  background: var(--color-gold);
1025	}
1026	
1027	
1028	/* ------------------------------------------------------------
1029	   14. FOOTER
1030	   ------------------------------------------------------------ */
1031	.site-footer {
1032	  position: relative;
1033	  z-index: var(--z-above);
1034	  background: #050505;
1035	  border-top: 1px solid var(--color-border);
1036	  padding: var(--space-8) 0;
1037	}
1038	
1039	.footer-inner {
1040	  max-width: var(--container-max);
1041	  margin-inline: auto;
1042	  padding-inline: var(--space-6);
1043	  display: flex;
1044	  align-items: center;
1045	  justify-content: space-between;
1046	  flex-wrap: wrap;
1047	  gap: var(--space-6);
1048	}
1049	
1050	.footer-logo {
1051	  font-family: var(--font-display);
1052	  font-size: 1rem;
1053	  letter-spacing: 0.15em;
1054	  text-transform: uppercase;
1055	  color: var(--color-text-muted);
1056	  transition: color var(--transition-fast);
1057	}
1058	
1059	.footer-logo:hover {
1060	  color: var(--color-text-primary);
1061	}
1062	
1063	.footer-links {
1064	  display: flex;
1065	  align-items: center;
1066	  gap: var(--space-6);
1067	  flex-wrap: wrap;
1068	}
1069	
1070	.footer-link {
1071	  font-size: var(--text-xs);
1072	  font-weight: var(--weight-medium);
1073	  letter-spacing: 0.10em;
1074	  text-transform: uppercase;
1075	  color: var(--color-text-muted);
1076	  transition: color var(--transition-fast);
1077	}
1078	
1079	.footer-link:hover {
1080	  color: var(--color-gold);
1081	}
1082	
1083	.footer-social {
1084	  display: flex;
1085	  align-items: center;
1086	  gap: var(--space-4);
1087	}
1088	
1089	.footer-social-link {
1090	  width: 32px;
1091	  height: 32px;
1092	  display: flex;
1093	  align-items: center;
1094	  justify-content: center;
1095	  border-radius: var(--radius-full);
1096	  border: 1px solid var(--color-border);
1097	  color: var(--color-text-muted);
1098	  transition:
1099	    color var(--transition-fast),
1100	    border-color var(--transition-fast),
1101	    box-shadow var(--transition-fast);
1102	}
1103	
1104	.footer-social-link:hover {
1105	  color: var(--color-gold);
1106	  border-color: var(--color-border-gold);
1107	  box-shadow: var(--shadow-gold);
1108	}
1109	
1110	.footer-copy {
1111	  width: 100%;
1112	  padding-top: var(--space-6);
1113	  border-top: 1px solid var(--color-border);
1114	  display: flex;
1115	  align-items: center;
1116	  justify-content: center;
1117	  font-size: var(--text-xs);
1118	  letter-spacing: 0.15em;
1119	  text-transform: uppercase;
1120	  color: var(--color-text-muted);
1121	}
1122	
1123	
1124	/* ------------------------------------------------------------
1125	   15. SCROLL-ANIMATION STATES
1126	   (GSAP setzt diese Klassen, CSS definiert die Zustände)
1127	   ------------------------------------------------------------ */
1128	
1129	/* Elemente die noch nicht sichtbar sind (initial state) */
1130	.reveal-up {
1131	  opacity: 0;
1132	  transform: translateY(30px);
1133	}
1134	
1135	.reveal-fade {
1136	  opacity: 0;
1137	}
1138	
1139	.reveal-left {
1140	  opacity: 0;
1141	  transform: translateX(-30px);
1142	}
1143	
1144	.reveal-right {
1145	  opacity: 0;
1146	  transform: translateX(30px);
1147	}
1148	
1149	/* GSAP animiert zu diesen Zuständen */
1150	.revealed {
1151	  opacity: 1;
1152	  transform: translateY(0) translateX(0);
1153	}
1154	
1155	
1156	/* ------------------------------------------------------------
1157	   16. UTILITY KLASSEN
1158	   ------------------------------------------------------------ */
1159	.visually-hidden {
1160	  position: absolute;
1161	  width: 1px;
1162	  height: 1px;
1163	  padding: 0;
1164	  margin: -1px;
1165	  overflow: hidden;
1166	  clip: rect(0, 0, 0, 0);
1167	  white-space: nowrap;
1168	  border: 0;
1169	}
1170	
1171	.text-center  { text-align: center; }
1172	.text-right   { text-align: right; }
1173	
1174	.mt-auto { margin-top: auto; }
1175	.ml-auto { margin-left: auto; }
1176	
1177	.w-full  { width: 100%; }
1178	.h-full  { height: 100%; }
1179	
1180	/* Aspect Ratios */
1181	.aspect-square  { aspect-ratio: 1 / 1; }
1182	.aspect-video   { aspect-ratio: 16 / 9; }
1183	.aspect-photo   { aspect-ratio: 4 / 3; }
1184	
1185	/* Overflow */
1186	.overflow-hidden  { overflow: hidden; }
1187	.overflow-clip    { overflow: clip; }
1188	
1189	
1190	/* ------------------------------------------------------------
1191	   17. RESPONSIVE BREAKPOINTS
1192	   ------------------------------------------------------------ */
1193	
1194	/* Tablet */
1195	@media (max-width: 1024px) {
1196	  :root {
1197	    --space-24: 5rem;
1198	    --space-32: 6rem;
1199	  }
1200	
1201	  .bento-grid--references {
1202	    grid-template-columns: 1fr;
1203	  }
1204	
1205	  .bento-grid--references .bento-item:first-child {
1206	    grid-row: span 1;
1207	  }
1208	
1209	  .nav-links {
1210	    gap: var(--space-4);
1211	  }
1212	}
1213	
1214	/* Mobile */
1215	@media (max-width: 768px) {
1216	  :root {
1217	    --container-max: 100%;
1218	    --space-24: 4rem;
1219	    --bento-gap: 10px;
1220	  }
1221	
1222	  .bento-grid--thirds {
1223	    grid-template-columns: 1fr;
1224	  }
1225	
1226	  .bento-grid--halves {
1227	    grid-template-columns: 1fr;
1228	  }
1229	
1230	  .footer-inner {
1231	    flex-direction: column;
1232	    align-items: flex-start;
1233	  }
1234	
1235	  /* Mobile Nav — Links ausgeblendet, Hamburger zeigen */
1236	  .nav-links {
1237	    display: none;
1238	  }
1239	
1240	  .nav-links.mobile-open {
1241	    display: flex;
1242	    flex-direction: column;
1243	    position: fixed;
1244	    inset: 0;
1245	    padding-top: var(--nav-height);
1246	    background: rgba(8, 8, 8, 0.98);
1247	    backdrop-filter: blur(20px);
1248	    z-index: calc(var(--z-nav) - 1);
1249	    align-items: center;
1250	    justify-content: center;
1251	    gap: var(--space-8);
1252	  }
1253	
1254	  .mobile-open .nav-link {
1255	    font-size: var(--text-xl);
1256	    letter-spacing: 0.08em;
1257	  }
1258	}
1259	
1260	
1261	/* ------------------------------------------------------------
1262	   18. REDUCED MOTION
1263	   ------------------------------------------------------------ */
1264	@media (prefers-reduced-motion: reduce) {
1265	  *, *::before, *::after {
1266	    animation-duration: 0.01ms !important;
1267	    animation-iteration-count: 1 !important;
1268	    transition-duration: 0.01ms !important;
1269	  }
1270	
1271	  .hero-scroll-hint {
1272	    animation: none;
1273	  }
1274	
1275	  html {
1276	    scroll-behavior: auto;
1277	  }
1278	}
1279

