file.content:
/* ============================================================
   MAXIWORX 2026 — components.css
   Hamburger, Mobile-Nav, Studio-Page, allgemeine Komponenten
   ============================================================ */

/* ------------------------------------------------------------
   HAMBURGER BUTTON
   ------------------------------------------------------------ */
.hamburger {
  display: none;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  gap: 5px;
  width: 36px;
  height: 36px;
  cursor: pointer;
  background: none;
  border: none;
  padding: 4px;
  z-index: 200;
  flex-shrink: 0;
}

.hamburger__line {
  display: block;
  width: 22px;
  height: 1.5px;
  background: rgba(240, 237, 232, 0.75);
  border-radius: 2px;
  transform-origin: center;
  transition: transform 300ms ease, opacity 300ms ease, width 300ms ease;
}

/* Aktiv-Zustand: X */
.hamburger.is-open .hamburger__line:nth-child(1) {
  transform: translateY(6.5px) rotate(45deg);
}
.hamburger.is-open .hamburger__line:nth-child(2) {
  opacity: 0;
  width: 0;
}
.hamburger.is-open .hamburger__line:nth-child(3) {
  transform: translateY(-6.5px) rotate(-45deg);
}

/* ------------------------------------------------------------
   MOBILE NAV OVERLAY
   ------------------------------------------------------------ */
.mobile-nav {
  position: fixed;
  inset: 0;
  z-index: 90;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 2.5rem;

  background: rgba(6, 6, 5, 0.97);
  backdrop-filter: blur(24px);
  -webkit-backdrop-filter: blur(24px);

  opacity: 0;
  pointer-events: none;
  transform: translateY(-12px);
  transition: opacity 350ms ease, transform 350ms ease;
}

.mobile-nav.is-open {
  opacity: 1;
  pointer-events: all;
  transform: translateY(0);
}

.mobile-nav__links {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.25rem;
  list-style: none;
}

.mobile-nav__link {
  font-family: 'Cormorant Garamond', serif;
  font-size: clamp(2rem, 7vw, 3rem);
  font-weight: 300;
  letter-spacing: 0.08em;
  color: rgba(240, 237, 232, 0.55);
  transition: color 200ms ease;
  padding: 0.4rem 1rem;
  display: block;
  text-align: center;
}

.mobile-nav__link:hover {
  color: #F0EDE8;
}

.mobile-nav__link.active {
  color: #C8922A;
}

.mobile-nav__divider {
  width: 40px;
  height: 1px;
  background: rgba(200, 146, 42, 0.25);
}

.mobile-nav__cta {
  font-family: 'Inter', sans-serif;
  font-size: 0.813rem;
  font-weight: 500;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: #fff;
  background: #3A7BD5;
  border: 1px solid #3A7BD5;
  border-radius: 9999px;
  padding: 0.75rem 2.5rem;

