/* ------------------------------------------------------------
   7. NAVIGATION
   ------------------------------------------------------------ */
.site-nav {
  position: fixed;
  top: 12px;
  left: 12px;
  right: 12px;
  z-index: var(--z-nav);
  height: var(--nav-height);
  display: flex;
  align-items: center;
  border-radius: var(--radius-xl);

  /* Pill immer sichtbar — subtiles Glas auch ganz oben */
  background: rgba(12, 12, 10, 0.55);
  backdrop-filter: blur(20px) saturate(1.2);
  -webkit-backdrop-filter: blur(20px) saturate(1.2);
  border: 1px solid rgba(255, 255, 255, 0.07);
  box-shadow: 0 4px 24px rgba(0, 0, 0, 0.35);

  transition: height      var(--transition-slow),
              background  var(--transition-slow),
              box-shadow  var(--transition-slow),
              top         var(--transition-slow);
}

/* Transparente Nav im Hero-Bereich — nicht mehr benötigt, aber als Fallback */
.site-nav--transparent {
  background: rgba(12, 12, 10, 0.45);
}

/* Stärkere Verglasung beim Scrollen — nav.js adds .nav--scrolled */
.site-nav--scrolled,
.site-nav.nav--scrolled {
  height: var(--nav-height-scrolled);
  top: 8px;
  background: rgba(12, 12, 10, 0.82);
  backdrop-filter: blur(32px) saturate(1.5);
  -webkit-backdrop-filter: blur(32px) saturate(1.5);

