2	const chokidar   = require('chokidar');
3	const SftpClient = require('ssh2-sftp-client');
4	const path       = require('path');
5	
6	// ---------------------------------------------------------------------------
7	// Config — all env vars coerced to plain strings
8	// ---------------------------------------------------------------------------
9	const SFTP_HOST        = String(process.env.SFTP_HOST        || '');
10	const SFTP_USER        = String(process.env.SFTP_USER        || '');
11	const SFTP_PASS        = String(process.env.SFTP_PASS        || '');
12	const SFTP_PORT        = String(process.env.SFTP_PORT        || '22');
13	// Remote base is always ./maxiworx regardless of what .env says
14	const SFTP_REMOTE_PATH = './maxiworx';
15	
16	if (!SFTP_HOST || !SFTP_USER || !SFTP_PASS) {
17	  console.error('[config] Missing SFTP_HOST, SFTP_USER or SFTP_PASS in .env');
18	  process.exit(1);
19	}
20	
21	const LOCAL_ROOT           = __dirname;
22	const QUEUE_DELAY_MS       = 500;   // pause between uploads
23	const CONNECT_DELAY_MS     = 1500;  // wait after startup before first connect
24	const HANDSHAKE_TIMEOUT_MS = 40000; // 40s — handles extreme mobile latency
25	const KEEPALIVE_MS         = 10000; // prevent idle-drop on hotspot
26	const MAX_RETRIES          = 3;     // reconnect attempts per file
27	
28	const CONNECT_OPTIONS = {
29	  host:              SFTP_HOST,
30	  port:              parseInt(SFTP_PORT, 10),
31	  username:          SFTP_USER,
32	  password:          SFTP_PASS,
33	  readyTimeout:      HANDSHAKE_TIMEOUT_MS,
34	  keepaliveInterval: KEEPALIVE_MS,
35	  // password-only — skip publickey / keyboard-interactive round-trips
36	  authHandler:       ['password'],
37	  tryKeyboard:       false,
38	  agent:             false,
39	  privateKey:        undefined,
40	};
41	
42	// ---------------------------------------------------------------------------
43	// Persistent SFTP connection with retry logic
44	// ---------------------------------------------------------------------------
45	const sftp = new SftpClient();
46	let connected = false;
47	
48	sftp.on('close', () => {
49	  connected = false;
50	  console.log('[sftp] connection closed — will reconnect on next upload');
51	});
52	sftp.on('error', (err) => {
53	  connected = false;
54	  console.error('[sftp] connection error:', err.message);
55	});
56	
57	async function ensureConnected(attempt = 1) {
58	  if (connected) return;
59	
60	  try {
61	    console.log(`[sftp] connecting to ${SFTP_HOST}:${SFTP_PORT} (attempt ${attempt}/${MAX_RETRIES})…`);
62	    await sftp.connect(CONNECT_OPTIONS);
63	    connected = true;
64	    console.log(`[sftp] connected to ${SFTP_HOST} → remote base: ${SFTP_REMOTE_PATH}`);
65	  } catch (err) {
66	    connected = false;
67	    console.error(`[sftp] connect failed (attempt ${attempt}): ${err.message}`);
68	
69	    if (attempt < MAX_RETRIES) {
70	      const backoff = attempt * 3000; // 3s, 6s between retries
71	      console.log(`[sftp] retrying in ${backoff / 1000}s…`);
72	      await new Promise(r => setTimeout(r, backoff));
73	      return ensureConnected(attempt + 1);
74	    }
75	
76	    throw new Error(`Could not connect after ${MAX_RETRIES} attempts: ${err.message}`);
77	  }
78	}
79	
80	// ---------------------------------------------------------------------------
81	// Serial upload queue
82	// ---------------------------------------------------------------------------
83	const queue  = [];
84	let running  = false;
85	
86	function enqueue(localPath) {
87	  if (!queue.includes(localPath)) {
88	    queue.push(localPath);
89	    console.log(`[queue]  +${path.relative(LOCAL_ROOT, localPath).replace(/\\/g, '/')} (${queue.length} pending)`);
90	  }
91	  if (!running) processQueue();
92	}
93	
94	async function processQueue() {
95	  if (queue.length === 0) { running = false; return; }
96	  running = true;
97	
98	  const localPath  = queue.shift();
99	  const relative   = path.relative(LOCAL_ROOT, localPath).replace(/\\/g, '/');
100	  const remotePath = `${SFTP_REMOTE_PATH}/${relative}`;
101	  const remoteDir  = remotePath.substring(0, remotePath.lastIndexOf('/'));
102	
103	  try {
104	    await ensureConnected();          // reconnects + retries if needed
105	    await sftp.mkdir(remoteDir, true);
106	    await sftp.put(localPath, remotePath);
107	    console.log(`[upload] ${relative} → ${remotePath}`);
108	  } catch (err) {
109	    console.error(`[error]  ${relative}: ${err.message}`);
110	    connected = false;                // force fresh connect for next file
111	  }
112	
113	  setTimeout(processQueue, QUEUE_DELAY_MS);
114	}
115	
116	// ---------------------------------------------------------------------------
117	// Chokidar watcher — armed after CONNECT_DELAY_MS
118	// ---------------------------------------------------------------------------
119	const IGNORED = [
120	  /(^|[/\\])\../,          // dot-files / dot-folders (.env, .git, etc.)
121	  /node_modules/,
122	  /watch\.js$/,
123	  /[/\\]logs([/\\]|$)/,   // cms/logs/ — never upload server logs
124	  /\.sql$/,                // SQL migrations — run manually on server
125	];
126	
127	const watcher = chokidar.watch(LOCAL_ROOT, {
128	  ignored:          IGNORED,
129	  persistent:       true,
130	  ignoreInitial:    true,
131	  awaitWriteFinish: { stabilityThreshold: 300, pollInterval: 100 },
132	});
133	
134	setTimeout(() => {
135	  watcher
136	    .on('add',    enqueue)
137	    .on('change', enqueue)
138	    .on('error',  (err) => console.error('[watcher error]', err));
139	
140	  console.log('');
141	  console.log(`[watch]  ${LOCAL_ROOT}`);
142	  console.log(`[target] ${SFTP_HOST}:${SFTP_PORT} → ${SFTP_REMOTE_PATH}`);
143	  console.log(`[config] handshake: ${HANDSHAKE_TIMEOUT_MS / 1000}s  keepalive: ${KEEPALIVE_MS / 1000}s  retries: ${MAX_RETRIES}  queue-delay: ${QUEUE_DELAY_MS}ms`);
144	  console.log('');
145	}, CONNECT_DELAY_MS);

