/**
 * Maxiworx — i18n.js (FIXED)
 *
 * ROOT CAUSE BUG (behoben):
 * Die alte Version lief applyLang() beim DOMContentLoaded und überschrieb
 * alle [data-i18n]-Elemente mit hardcodierten Strings — NACH dem PHP-Rendering.
 * Dadurch wurden DB-Werte aus c($c, 'hero.pre') sofort wieder überschrieben.
 *
 * FIX:
 * - Elemente die AUCH data-cms-key haben → werden vom JS NICHT angefasst.
 *   PHP hat dort bereits den DB-Wert geschrieben.
 * - Elemente die NUR data-i18n haben (nav-links, footer etc.) → JS übersetzt.
 * - Slideshow-Captions werden aus data-caption-de/en gelesen (PHP schreibt diese).
 */
(function () {
  'use strict';

  /* ---- Nur UI-Chrome übersetzen (NIE CMS-Inhalte) ---- */
  const uiTranslations = {
    de: {
      // Nav (fest, kein CMS)
      'nav.studio':    'Studio',
      'nav.equipment': 'Equipment',
      'nav.sessions':  'Sessions & Rates',
      'nav.specials':  'Specials',
      'nav.references':'Referenzen',
      'nav.book':      'Book Session',
      'nav.home':      'Home',
      // Hero UI
      'hero.scroll':   'Scroll',
      // Contact form labels (kein CMS)
      'contact.emailLabel': 'Deine E-Mail-Adresse',
      'contact.submit': 'Anfrage senden',
      // Footer (fest)
      'footer.imprint': 'Impressum',
      'footer.privacy': 'Datenschutz',
      'footer.terms':   'AGB',
    },
    en: {
      'nav.studio':    'Studio',
      'nav.equipment': 'Equipment',
      'nav.sessions':  'Sessions & Rates',
      'nav.specials':  'Specials',
      'nav.references':'References',
      'nav.book':      'Book Session',
      'nav.home':      'Home',
      'hero.scroll':   'Scroll',
      'contact.emailLabel': 'Your Email Address',
      'contact.submit': 'Send Inquiry',
      'footer.imprint': 'Imprint',
      'footer.privacy': 'Privacy Policy',
      'footer.terms':   'Terms',
    }
  };

  /* ---- Flags ---- */
  const flagDE = `<svg viewBox="0 0 20 20" xmlns="http://www.w3.org/2000/svg">
    <rect width="20" height="6.67" y="0"     fill="#000000"/>
    <rect width="20" height="6.67" y="6.67"  fill="#DD0000"/>
    <rect width="20" height="6.67" y="13.33" fill="#FFCE00"/>
  </svg>`;
  const flagEN = `<svg viewBox="0 0 20 20" xmlns="http://www.w3.org/2000/svg">
    <rect width="20" height="20" fill="#012169"/>
    <line x1="10" y1="0" x2="10" y2="20" stroke="#ffffff" stroke-width="3"/>
    <line x1="0"  y1="10" x2="20" y2="10" stroke="#ffffff" stroke-width="3"/>
    <line x1="0" y1="0" x2="20" y2="20" stroke="#ffffff" stroke-width="2.2"/>
    <line x1="20" y1="0" x2="0"  y2="20" stroke="#ffffff" stroke-width="2.2"/>
    <line x1="0" y1="0" x2="20" y2="20" stroke="#C8102E" stroke-width="1.2"/>
    <line x1="20" y1="0" x2="0"  y2="20" stroke="#C8102E" stroke-width="1.2"/>
    <line x1="10" y1="0" x2="10" y2="20" stroke="#C8102E" stroke-width="1.8"/>
    <line x1="0"  y1="10" x2="20" y2="10" stroke="#C8102E" stroke-width="1.8"/>
  </svg>`;

  let currentLang = localStorage.getItem('mxw_lang') || document.documentElement.lang || 'de';

  function applyLang(lang) {
    currentLang = lang;
    localStorage.setItem('mxw_lang', lang);
    document.documentElement.lang = lang;

    const t = uiTranslations[lang] || uiTranslations.de;

    /*
     * KEY FIX: Nur Elemente übersetzen die NICHT data-cms-key haben.
     * Elemente mit data-cms-key wurden bereits durch PHP/DB befüllt.
     */
    document.querySelectorAll('[data-i18n]').forEach(el => {
      if (el.hasAttribute('data-cms-key')) return; // DB-Content — NICHT überschreiben
      const key = el.getAttribute('data-i18n');
      if (t[key] !== undefined) {
        el.innerHTML = t[key];
      }
    });

    updateCaption();

    // Flag aktualisieren
    const flagEl = document.getElementById('lang-flag-current');
    if (flagEl) {
      flagEl.innerHTML = lang === 'de' ? flagDE : flagEN;
    }

    // Aktive Option markieren
    document.querySelectorAll('.lang-option').forEach(opt => {
      opt.classList.toggle('active', opt.dataset.lang === lang);
    });

    // Lang-Wechsel an PHP senden → Session aktualisieren
    fetch(`/maxiworx/?lang=${lang}`, { method: 'GET', credentials: 'same-origin' });
  }

  function updateCaption() {
    const activeSlide = document.querySelector('.slide.active');
    const captionEl   = document.getElementById('slide-caption');
    if (!activeSlide || !captionEl) return;
    const caption = activeSlide.getAttribute(`data-caption-${currentLang}`)
                 || activeSlide.getAttribute('data-caption-de')
                 || '';
    captionEl.style.opacity = '0';
    setTimeout(() => {
      captionEl.textContent = caption;
      captionEl.style.opacity = '1';
    }, 200);
  }

  window.updateSlideCaptionI18n = updateCaption;

  /* ---- Dropdown ---- */
  const btn      = document.getElementById('lang-btn');
  const dropdown = document.getElementById('lang-dropdown');

  btn?.addEventListener('click', (e) => {
    e.stopPropagation();
    const isOpen = dropdown.classList.toggle('open');
    btn.setAttribute('aria-expanded', isOpen);
  });

  document.addEventListener('click', () => {
    dropdown?.classList.remove('open');
    btn?.setAttribute('aria-expanded', 'false');
  });

  document.querySelectorAll('.lang-option').forEach(opt => {
    opt.addEventListener('click', (e) => {
      e.stopPropagation();
      applyLang(opt.dataset.lang);
      dropdown.classList.remove('open');
      btn.setAttribute('aria-expanded', 'false');
    });
  });

  /* Initial — NACH DOMContentLoaded damit PHP-Werte bereits im DOM stehen */
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', () => applyLang(currentLang));
  } else {
    applyLang(currentLang);
  }

})();

