/* ============================================================
   SETTINGS DROPDOWN (Zahnrad)
============================================================ */
const settingsBtn      = document.getElementById('settings-btn');
const settingsDropdown = document.getElementById('settings-dropdown');
const settingsWrap     = document.getElementById('settings-wrap');

function openSettings() {
  settingsDropdown?.classList.add('is-open');
  settingsBtn?.setAttribute('aria-expanded', 'true');
}

function closeSettings() {
  settingsDropdown?.classList.remove('is-open');
  settingsBtn?.setAttribute('aria-expanded', 'false');
}

settingsBtn?.addEventListener('click', (e) => {
  e.stopPropagation();
  settingsDropdown?.classList.contains('is-open') ? closeSettings() : openSettings();
});

/* Klick außerhalb schließt Dropdown */
document.addEventListener('click', (e) => {
  if (settingsWrap && !settingsWrap.contains(e.target)) closeSettings();
});

/* ESC schließt auch das Settings-Dropdown */
document.addEventListener('keydown', e => {
  if (e.key === 'Escape') closeSettings();
});

/* ============================================================
   DARK / LIGHT MODE
============================================================ */
function applyTheme(theme) {
  if (theme === 'light') {
    document.documentElement.dataset.theme = 'light';
  } else {
    delete document.documentElement.dataset.theme;
  }
  localStorage.setItem('mxw_theme', theme);

  /* Aktive Buttons synchronisieren (Desktop + Mobile) */
  document.querySelectorAll('.settings-opt--mode, .mobile-settings-opt--mode').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.mode === theme);
  });
}

