/**
 * Maxiworx — nav.js
 * Einbinden auf JEDER Unterseite.
 * Enthält: Nav-Scroll-Effekt, Hero-Animation, Hamburger, Slideshow, Scroll-Reveal.
 */
(function () {
  'use strict';

  /* ============================================================
     NAV SCROLL-EFFEKT & HERO-ANIMATION
  ============================================================ */
  const nav         = document.getElementById('site-nav');
  const heroTitle   = document.getElementById('hero-title');
  const heroTagline = document.getElementById('hero-tagline');
  const heroPre     = document.querySelector('.hero-pre');
  const navLogo     = document.querySelector('.nav-logo');
  const navSub      = document.querySelector('.nav-brand-sub');
  const navDivider  = document.querySelector('.nav-brand-divider');

  /* Nav-Logo startet unsichtbar (nur auf Main-Page mit Hero) */
  const hasHero = !!heroTitle;

  if (hasHero && navLogo) {
    navLogo.style.opacity   = '0';
    navLogo.style.transform = 'translateY(8px)';
    navLogo.style.transition = 'none';
    requestAnimationFrame(() => {
      navLogo.style.transition = 'opacity 350ms ease, transform 350ms ease';
    });
  }

  /* CSS-Animation abwarten, dann JS übernehmen */
  let jsReady = !hasHero; /* Auf Unterseiten sofort ready */
  if (hasHero) {
    setTimeout(() => {
      jsReady = true;
      [heroTitle, heroTagline, heroPre].forEach(el => {
        if (!el) return;
        el.style.animation  = 'none';
        el.style.opacity    = '1';
        el.style.transform  = 'translateY(0)';
        el.style.willChange = 'transform, opacity';
      });
    }, 1650);
  }

  const START = 40;
  const END   = 280;

  function clamp(v)       { return Math.min(Math.max(v, 0), 1); }
  function lerp(a, b, t)  { return a + (b - a) * clamp(t); }
  function prog(y, s, e)  { return clamp((y - s) / (e - s)); }

  function onScroll() {
    const y = window.scrollY;
    const t = prog(y, START, END);

    /* Nav Glas */
    nav?.classList.toggle('nav--scrolled', y > START);

    if (!jsReady || !hasHero) return;

    /* Hero-Titel */
    if (heroTitle) {
      heroTitle.style.transform = `translateY(${lerp(0, -100, t)}px)`;
      heroTitle.style.opacity   = lerp(1, 0, t * 1.4).toFixed(3);
    }
    /* Tagline */
    if (heroTagline) {
      const tg = prog(y, START, END * 0.6);
      heroTagline.style.transform = `translateY(${lerp(0, -50, tg)}px)`;
      heroTagline.style.opacity   = lerp(1, 0, tg * 1.6).toFixed(3);
    }
    /* Pre-Text */
    if (heroPre) {
      const tp = prog(y, START, END * 0.4);
      heroPre.style.transform = `translateY(${lerp(0, -30, tp)}px)`;
      heroPre.style.opacity   = lerp(1, 0, tp * 2).toFixed(3);
    }
    /* Nav-Logo einblenden */
    if (navLogo) {
      const lt = prog(y, END * 0.35, END * 0.85);
      navLogo.style.opacity   = lt.toFixed(3);
      navLogo.style.transform = `translateY(${lerp(8, 0, lt)}px)`;
    }
    /* Nav-Sub */
    const st = prog(y, END * 0.80, END);
    if (navSub)     { navSub.style.maxWidth = st > 0 ? '260px' : '0'; navSub.style.opacity = st.toFixed(3); }
    if (navDivider) { navDivider.style.opacity = st.toFixed(3); }
  }

  window.addEventListener('scroll', onScroll, { passive: true });
  onScroll();

  /* ============================================================
     HAMBURGER MENÜ
  ============================================================ */
  const hamburger  = document.getElementById('hamburger');
  const mobileNav  = document.getElementById('mobile-nav');
  const body       = document.body;

  function openMobileNav() {
    hamburger?.classList.add('is-open');
    mobileNav?.classList.add('is-open');
    hamburger?.setAttribute('aria-expanded', 'true');
    body.style.overflow = 'hidden'; /* Scrollen sperren */
  }

  function closeMobileNav() {
    hamburger?.classList.remove('is-open');
    mobileNav?.classList.remove('is-open');
    hamburger?.setAttribute('aria-expanded', 'false');
    body.style.overflow = '';
  }

  function toggleMobileNav() {
    mobileNav?.classList.contains('is-open') ? closeMobileNav() : openMobileNav();
  }

  hamburger?.addEventListener('click', toggleMobileNav);

  /* Links im Mobile-Nav → Menü schließen */
  mobileNav?.querySelectorAll('a, button.mobile-nav__cta').forEach(el => {
    el.addEventListener('click', closeMobileNav);
  });

  /* ESC schließt Menü */
  document.addEventListener('keydown', e => {
    if (e.key === 'Escape') closeMobileNav();
  });

  /* Mobile Sprach-Buttons */
  document.querySelectorAll('.mobile-lang-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      const lang = btn.dataset.lang;
      if (typeof applyLang === 'function') applyLang(lang);
      /* i18n.js übernimmt, hier nur visuelles Update */
      document.querySelectorAll('.mobile-lang-btn').forEach(b => b.classList.toggle('active', b.dataset.lang === lang));
      closeMobileNav();
    });
  });

  /* ============================================================
     SCROLL REVEAL
  ============================================================ */
  const revealEls = document.querySelectorAll('[data-reveal]');
  if (revealEls.length) {
    const observer = new IntersectionObserver((entries) => {
      entries.forEach((entry, i) => {
        if (entry.isIntersecting) {
          setTimeout(() => entry.target.classList.add('is-revealed'), i % 3 * 80);
          observer.unobserve(entry.target);
        }
      });
    }, { threshold: 0.08, rootMargin: '0px 0px -30px 0px' });
    revealEls.forEach(el => observer.observe(el));
  }

  /* ============================================================
     SLIDESHOW (nur Main-Page)
  ============================================================ */
  const slides = document.querySelectorAll('.slide');
  const dots   = document.querySelectorAll('.slide-dot');
  let current  = 0;
  let timer    = null;

  function goTo(index) {
    slides[current]?.classList.remove('active');
    dots[current]?.classList.remove('active');
    current = (index + slides.length) % slides.length;
    slides[current]?.classList.add('active');
    dots[current]?.classList.add('active');
    if (typeof window.updateSlideCaptionI18n === 'function') window.updateSlideCaptionI18n();
  }

  function startAuto() { timer = setInterval(() => goTo(current + 1), 5000); }

  if (slides.length) {
    goTo(0);
    startAuto();
    dots.forEach((dot, i) => dot.addEventListener('click', () => { clearInterval(timer); goTo(i); startAuto(); }));
    document.querySelector('.slide-prev')?.addEventListener('click', () => { clearInterval(timer); goTo(current - 1); startAuto(); });
    document.querySelector('.slide-next')?.addEventListener('click', () => { clearInterval(timer); goTo(current + 1); startAuto(); });
  }

})();

