.blog-card__thumb-icon { opacity: 0.10; }
.blog-card__thumb-icon svg { width: 40px; height: 40px; color: #F0EDE8; }

.blog-card__body { padding: 1.5rem 1.75rem 1.75rem; display: flex; flex-direction: column; flex: 1; }
.blog-card__meta { display: flex; align-items: center; gap: 0.75rem; margin-bottom: 0.875rem; }
.blog-card__cat {
  font-size: 0.575rem; font-weight: 600; letter-spacing: 0.18em; text-transform: uppercase;
