/* Header */
.ab-header { display: flex; align-items: flex-start; justify-content: space-between; gap: 1.5rem; margin-bottom: 2rem; flex-wrap: wrap; }
.ab-label { font-size: 0.688rem; font-weight: 500; letter-spacing: 0.25em; text-transform: uppercase; color: #C8922A; margin-bottom: 0.5rem; }
.ab-title { font-family: 'Cormorant Garamond', serif; font-size: clamp(1.2rem,2.5vw,1.65rem); font-weight: 300; color: #F0EDE8; line-height: 1.2; }
