/* Loading indicator */
.ab-loading { display: flex; flex-direction: column; align-items: flex-end; gap: 0.15rem; flex-shrink: 0; transition: opacity 500ms ease, visibility 500ms ease; }
.ab-loading.is-ready { opacity: 0; visibility: hidden; pointer-events: none; }
.ab-loading__pct { font-family: 'Cormorant Garamond', serif; font-size: 2.2rem; font-weight: 300; line-height: 1; color: #C8922A; letter-spacing: -0.02em; }
.ab-loading__label { font-size: 0.55rem; font-weight: 500; letter-spacing: 0.22em; text-transform: uppercase; color: rgba(255,255,255,0.22); }

/* Waveform area */
.ab-waveform-wrap {
  position: relative; height: 90px;
  background: rgba(0,0,0,0.28); border-radius: 10px; overflow: hidden;
  border: 1px solid rgba(255,255,255,0.05); margin-bottom: 0.875rem; cursor: pointer;
}
.ab-canvas { position: absolute; inset: 0; display: block; width: 100%; height: 100%; }

